// ─── Notification / Toast System ─────────────────────────────────────────────
const NotifCtx = React.createContext({ add:()=>{}, items:[] });
const useNotif = () => React.useContext(NotifCtx);

function NotifProvider({ children }) {
  const T = useT();
  const [items, setItems] = React.useState([]);
  const [drawer, setDrawer] = React.useState(false);

  const add = React.useCallback((msg, type="info", opts={}) => {
    const id = Date.now().toString(36) + Math.random().toString(36).slice(2,5);
    const item = { id, msg, type, ts: new Date().toISOString(),
                   read: false, persistent: opts.persistent||false,
                   action: opts.action||null, actionLabel: opts.actionLabel||null };
    setItems(p => [item, ...p].slice(0, 50));
    // Auto-dismiss non-persistent toasts
    if (!opts.persistent) {
      setTimeout(() => setItems(p => p.filter(i => i.id !== id)), opts.duration||4500);
    }
    return id;
  }, []);

  const dismiss = React.useCallback((id) => setItems(p => p.filter(i => i.id !== id)), []);
  const markRead = React.useCallback((id) => setItems(p => p.map(i => i.id===id?{...i,read:true}:i)), []);
  const markAllRead = React.useCallback(() => setItems(p => p.map(i => ({...i,read:true}))), []);
  const clearAll = React.useCallback(() => setItems([]), []);
  const unread = items.filter(i => !i.read).length;

  const TYPE_STYLE = {
    success: { bg:"#10B981", icon:"✓" },
    error:   { bg:"#EF4444", icon:"✗" },
    warning: { bg:"#F59E0B", icon:"⚠" },
    info:    { bg:"#6366F1", icon:"ℹ" },
    run:     { bg:"#8B5CF6", icon:"▶" },
  };

  return (
    <NotifCtx.Provider value={{ add, items, unread, drawer, setDrawer, markRead, markAllRead, clearAll, dismiss }}>
      {children}

      {/* Toast stack — bottom-right */}
      <div style={{ position:"fixed", bottom:24, right:24, zIndex:9999,
        display:"flex", flexDirection:"column", gap:8, pointerEvents:"none",
        maxWidth:360 }}>
        {items.filter(i=>!i.read&&!i.persistent).slice(0,4).map(item => {
          const s = TYPE_STYLE[item.type] || TYPE_STYLE.info;
          return (
            <div key={item.id}
              className="wz-toast-enter"
              style={{ display:"flex", alignItems:"flex-start", gap:10,
                padding:"12px 14px", borderRadius:10, pointerEvents:"all",
                background: T.isDark ? T.card : "#1A1C23",
                color:"white",
                boxShadow:"0 8px 32px rgba(0,0,0,0.4)",
                border:`1px solid rgba(255,255,255,0.09)`,
                animation:"slideIn 0.2s ease",
                maxWidth:360 }}>
              <div style={{ width:22, height:22, borderRadius:6, flexShrink:0,
                background:s.bg, display:"flex", alignItems:"center",
                justifyContent:"center", fontSize:11, fontWeight:700, color:"white",
                marginTop:1 }}>{s.icon}</div>
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontSize:12, fontWeight:500, color:"rgba(255,255,255,0.92)",
                  lineHeight:1.4, wordBreak:"break-word" }}>{item.msg}</div>
                {item.action && (
                  <button onClick={item.action}
                    style={{ marginTop:5, fontSize:11, color:s.bg, background:"none",
                      border:"none", cursor:"pointer", padding:0, fontWeight:600 }}>
                    {item.actionLabel||"View →"}
                  </button>
                )}
              </div>
              <button onClick={()=>dismiss(item.id)}
                style={{ background:"none", border:"none", cursor:"pointer",
                  color:"rgba(255,255,255,0.35)", fontSize:16, lineHeight:1,
                  padding:0, flexShrink:0, marginTop:1 }}>×</button>
            </div>
          );
        })}
      </div>

      {/* Notification Drawer */}
      {drawer && (
        <div style={{ position:"fixed", inset:0, zIndex:8000 }}
          onClick={()=>setDrawer(false)}>
          <div style={{ position:"absolute", top:0, right:0, width:380, height:"100%",
            background:T.card, boxShadow:"-8px 0 32px rgba(0,0,0,0.2)",
            display:"flex", flexDirection:"column",
            borderLeft:`1px solid ${T.border2}` }}
            onClick={e=>e.stopPropagation()}>

            {/* Header */}
            <div style={{ padding:"16px 20px", borderBottom:`1px solid ${T.border}`,
              display:"flex", alignItems:"center", gap:10 }}>
              <Bell size={15} color={T.muted}/>
              <span style={{ fontSize:14, fontWeight:700, color:T.text, flex:1 }}>
                Notifications
              </span>
              {unread > 0 && (
                <button onClick={markAllRead}
                  style={{ fontSize:11, color:"#6366F1", background:"none",
                    border:"none", cursor:"pointer", fontWeight:600 }}>
                  Mark all read
                </button>
              )}
              {items.length > 0 && (
                <button onClick={clearAll}
                  style={{ fontSize:11, color:"#9CA3AF", background:"none",
                    border:"none", cursor:"pointer" }}>
                  Clear
                </button>
              )}
              <button onClick={()=>setDrawer(false)}
                style={{ background:"none", border:"none", cursor:"pointer",
                  color:T.muted, fontSize:18, lineHeight:1 }}>×</button>
            </div>

            {/* Items */}
            <div style={{ flex:1, overflowY:"auto" }}>
              {items.length === 0 ? (
                <div style={{ textAlign:"center", padding:"60px 24px", color:T.muted }}>
                  <Bell size={32} color={T.dim} style={{ opacity:0.4, marginBottom:12, display:"block", margin:"0 auto 12px" }}/>
                  <div style={{ fontSize:13, fontWeight:600, color:T.text2 }}>All caught up</div>
                  <div style={{ fontSize:11, marginTop:4, color:T.muted }}>No notifications yet</div>
                </div>
              ) : items.map(item => {
                const s = TYPE_STYLE[item.type] || TYPE_STYLE.info;
                return (
                  <div key={item.id} onClick={()=>markRead(item.id)}
                    style={{ padding:"12px 20px", borderBottom:`1px solid ${T.border}`,
                      display:"flex", gap:10, cursor:"pointer",
                      background: item.read ? "transparent" : `${T.accent}06`,
                      transition:"background 0.1s" }}
                    onMouseEnter={e=>e.currentTarget.style.background=`${T.accent}08`}
                    onMouseLeave={e=>e.currentTarget.style.background=item.read?"transparent":`${T.accent}06`}>
                    <div style={{ width:22, height:22, borderRadius:6, flexShrink:0,
                      background:s.bg, display:"flex", alignItems:"center",
                      justifyContent:"center", fontSize:11, fontWeight:700,
                      color:"white", marginTop:2 }}>{s.icon}</div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:12, color:T.text, lineHeight:1.4 }}>{item.msg}</div>
                      <div style={{ fontSize:10, color:T.dim, marginTop:3 }}>
                        {new Date(item.ts).toLocaleTimeString()}
                      </div>
                      {item.action && (
                        <button onClick={(e)=>{e.stopPropagation();item.action();}}
                          style={{ marginTop:4, fontSize:11, color:s.bg, background:"none",
                            border:"none", cursor:"pointer", padding:0, fontWeight:600 }}>
                          {item.actionLabel||"View →"}
                        </button>
                      )}
                    </div>
                    {!item.read && (
                      <div style={{ width:7, height:7, borderRadius:"50%",
                        background:"#6366F1", flexShrink:0, marginTop:6 }}/>
                    )}
                    <button onClick={(e)=>{e.stopPropagation();dismiss(item.id);}}
                      style={{ background:"none", border:"none", cursor:"pointer",
                        color:T.muted, fontSize:14, lineHeight:1, flexShrink:0 }}>×</button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </NotifCtx.Provider>
  );
}

// Bell button — used in Sidebar
function BellButton({ collapsed }) {
  const T = useT();
  const { unread, setDrawer } = useNotif();
  return (
    <button onClick={()=>setDrawer(d=>!d)}
      title="Notifications"
      style={{ width:"100%", display:"flex", alignItems:"center",
        gap: collapsed ? 0 : 10,
        padding: collapsed ? "8px 0" : "8px 10px",
        justifyContent: collapsed ? "center" : "flex-start",
        borderRadius:7, border:"none",
        background: unread > 0 ? `${T.navActiveBg||T.accent+"18"}` : "transparent",
        color: unread > 0 ? (T.navActiveText||T.accent) : "rgba(255,255,255,0.4)",
        cursor:"pointer", transition:"all 0.15s", fontFamily:"inherit",
        position:"relative" }}
      onMouseEnter={e=>{e.currentTarget.style.background="rgba(255,255,255,0.05)";e.currentTarget.style.color="rgba(255,255,255,0.7)";}}
      onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color="rgba(255,255,255,0.4)";}}>
      <div style={{ position:"relative", flexShrink:0 }}>
        <Bell size={14} strokeWidth={1.8}/>
        {unread > 0 && (
          <div style={{ position:"absolute", top:-4, right:-4,
            width:14, height:14, borderRadius:99, background:"#EF4444",
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:8, fontWeight:700, color:"white" }}>
            {unread > 9 ? "9+" : unread}
          </div>
        )}
      </div>
      {!collapsed && (
        <span style={{ fontSize:12, fontWeight:400, flex:1 }}>Notifications</span>
      )}
      {!collapsed && unread > 0 && (
        <span style={{ minWidth:18, height:18, borderRadius:99, padding:"0 5px",
          background:"#EF4444", color:"white", fontSize:9, fontWeight:700,
          display:"flex", alignItems:"center", justifyContent:"center" }}>
          {unread}
        </span>
      )}
    </button>
  );
}

const PASS_CONDITIONS = [
  { value:"rows = 0",    label:"rows = 0  — no bad records returned" },
  { value:"rows > 0",    label:"rows > 0  — data must be present" },
  { value:"rows > 1",    label:"rows > 1  — more than one row" },
  { value:"rows > 10",   label:"rows > 10 — at least 10 rows" },
  { value:"rows > 100",  label:"rows > 100 — at least 100 rows" },
  { value:"value = 0",   label:"value = 0  — first cell equals zero" },
  { value:"value > 0",   label:"value > 0  — first cell greater than zero" },
  { value:"value > 1",   label:"value > 1  — first cell greater than one" },
  { value:"value >= 95", label:"value ≥ 95 — percentage / score threshold" },
  { value:"custom",      label:"✏ Custom expression…" },
];

// Helper: render a smart pass-condition picker (dropdown + optional freetext)
function PassConditionPicker({ value, onChange, style }) {
  const T = useT();
  // Detect if current value matches a preset
  const isPreset = PASS_CONDITIONS.some(p => p.value !== "custom" && p.value === value);
  const isCustom = !isPreset;
  const [mode, setMode] = React.useState(isCustom ? "custom" : "preset");
  const [customVal, setCustomVal] = React.useState(isCustom ? value : "");

  const inp = {
    padding:"6px 10px", borderRadius:6, fontSize:11,
    border:`1px solid ${T.border}`, background:T.surface, color:T.text,
    fontFamily:"inherit", outline:"none", boxSizing:"border-box",
    width:"100%", ...style,
  };

  const handlePresetChange = (v) => {
    if (v === "custom") { setMode("custom"); }
    else { setMode("preset"); onChange(v); }
  };
  const handleCustomChange = (v) => {
    setCustomVal(v);
    onChange(v);
  };

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
      <select
        value={mode === "custom" ? "custom" : value}
        onChange={e => handlePresetChange(e.target.value)}
        style={inp}
      >
        {PASS_CONDITIONS.map(o => (
          <option key={o.value} value={o.value}>{o.label}</option>
        ))}
      </select>
      {mode === "custom" && (
        <div>
          <input
            value={customVal}
            onChange={e => handleCustomChange(e.target.value)}
            placeholder='e.g. rows > 50  or  value >= 0.95  or  rows = 0'
            style={{ ...inp, fontFamily:"monospace", fontSize:11 }}
            onFocus={e => e.target.style.borderColor = T.accent}
            onBlur={e => e.target.style.borderColor = T.border}
          />
          <div style={{ fontSize:9, color:T.muted, marginTop:3 }}>
            Format: <code style={{fontFamily:"monospace"}}>rows OP N</code> or <code style={{fontFamily:"monospace"}}>value OP N</code> — e.g. <code style={{fontFamily:"monospace"}}>rows &gt; 50</code>, <code style={{fontFamily:"monospace"}}>value &gt;= 0.9</code>
          </div>
        </div>
      )}
    </div>
  );
}

const SEV_COLOR = { critical:"#ef4444", high:"#f97316", medium:"#eab308", low:"#06b6d4", info:"#6366f1" };
const SEV_BG    = { critical:"#fef2f2", high:"#fff7ed", medium:"#fefce8", low:"#ecfeff", info:"#eef2ff" };

// ── WorkflowsTab — main entry point ──────────────────────────────────────────
function WorkflowsTab({ navigateTo }) {
  const T = useT();
  const dbSchema = useSchema();

  const [view,       setView]    = React.useState("list"); // list | builder | detail | runs
  const [workflows,  setWfs]     = React.useState([]);
  const [editingWf,  setEditing] = React.useState(null);
  const [detailWf,   setDetail]  = React.useState(null);
  const [loading,    setLoading] = React.useState(false);
  const [runHistory, setHistory] = useLocal("wz_wf_runhistory_v1", []); // persisted run history
  const [running,    setRunning] = React.useState({}); // {wf_id: bool}
  const [liveRun,    setLiveRun] = React.useState(null); // latest run result being shown

  // Load workflows + history from backend
  const load = async (seed=false) => {
    try {
      if (seed) await fetch(`${API}/api/custom-workflows/load-from-db`).catch(()=>{});
      const [wfsRes, histRes] = await Promise.all([
        fetch(`${API}/api/custom-workflows`).then(r=>r.json()),
        fetch(`${API}/api/custom-workflows/history/v2?limit=100`).then(r=>r.json()).catch(()=>[]),
      ]);
      if (Array.isArray(wfsRes)) {
        setWfs(wfsRes);
        if (seed) {
          const existingIds = wfsRes.map(w=>w.id);
          await seedBuiltins(existingIds);
          // Reload after seeding
          const fresh = await fetch(`${API}/api/custom-workflows`).then(r=>r.json()).catch(()=>[]);
          if (Array.isArray(fresh)) setWfs(fresh);
        }
      }
      if (Array.isArray(histRes)) setHistory(histRes);
    } catch(e) {}
  };

  React.useEffect(() => {
    load(true); // seed on first load
    const id = setInterval(()=>load(false), 20000);
    return () => clearInterval(id);
  }, []);

  const [saveError, setSaveError] = React.useState(null);
  const saveWf = async (wf) => {
    setSaveError(null);
    try {
      const res  = await fetch(`${API}/api/custom-workflows/save/v2`, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify(wf)
      });
      const data = await res.json();
      if (data.error) { setSaveError(String(data.error)); return; }
      if (data.workflow) {
        setWfs(p => {
          const idx = p.findIndex(w=>w.id===data.workflow.id);
          return idx>=0 ? p.map((w,i)=>i===idx?data.workflow:w) : [...p, data.workflow];
        });
        setView("list");
        setEditing(null);
      }
    } catch(e) {
      setSaveError(e.message);
    }
  };

  const [undoQueue, setUndoQueue] = React.useState([]); // [{wf, timer}]

  // Clear pending undo timers on unmount to prevent setState on unmounted component
  React.useEffect(() => {
    return () => undoQueue.forEach(u => clearTimeout(u.timer));
  }, [undoQueue]);

  const deleteWf = async (id) => {
    const wf = workflows.find(w=>w.id===id) || wfs.find(w=>w.id===id);
    if (!wf) return;
    // Optimistically remove from UI
    setWfs(p=>p.filter(w=>w.id!==id));
    // Show undo toast
    const undoTimer = setTimeout(async () => {
      // Commit delete after 6s
      await fetch(`${API}/api/custom-workflows/${id}`, {method:"DELETE"}).catch(()=>{});
      setUndoQueue(q=>q.filter(u=>u.id!==id));
    }, 6000);
    setUndoQueue(q=>[...q, {id, wf, timer:undoTimer}]);
  };

  const undoDelete = (id) => {
    const entry = undoQueue.find(u=>u.id===id);
    if (!entry) return;
    clearTimeout(entry.timer);
    setUndoQueue(q=>q.filter(u=>u.id!==id));
    setWfs(p=>[entry.wf, ...p]);
  };

  const { add: addNotif } = useNotif();
  const runWf = async (wf) => {
    // Navigate to detail immediately — show loading state there
    setDetail(wf);
    setLiveRun(null);
    setView("detail");
    setRunning(p=>({...p,[wf.id]:true}));
    addNotif(`Running: ${wf.name}…`, "run");
    try {
      const res  = await fetch(`${API}/api/custom-workflows/${wf.id}/run/v2`, {method:"POST"});
      const data = await res.json();
      if (data.error) {
        addNotif(`${wf.name}: ${data.error}`, "error", {persistent:true});
      } else {
        setHistory(p=>[data,...p].slice(0,200));
        setLiveRun(data);
        const failed = data.failed || 0;
        if (failed > 0) {
          addNotif(`${wf.name}: ${failed} check${failed!==1?"s":""} failed`, "error", {
            persistent:true, actionLabel:"View results", action:()=>setView("detail")
          });
          // ⚡ Signal event-driven pipelines
          window.dispatchEvent(new CustomEvent("wz_failure_detected", { detail:{ source:"workflow", name:wf.name, failed } }));
        } else {
          addNotif(`${wf.name}: all checks passed ✓`, "success");
        }
      }
    } catch(e) {
      addNotif(`${wf.name}: run error — ${e.message}`, "error", {persistent:true});
    }
    setRunning(p=>({...p,[wf.id]:false}));
  };

  const toggleEnabled = async (wf) => {
    const updated = {...wf, enabled: !wf.enabled};
    await fetch(`${API}/api/custom-workflows/save/v2`, {
      method:"POST", headers:{"Content-Type":"application/json"},
      body:JSON.stringify(updated)
    }).catch(()=>{});
    setWfs(p=>p.map(w=>w.id===wf.id?updated:w));
  };

  // ── Built-in workflows ──────────────────────────────────────────────────────
  const [sopRunning,     setSopRunning]     = React.useState(false);
  const [sopResult,      setSopResult]      = useSession("wz_sopResult", null);
  const [aiSuggestions,  setAiSuggestions]  = React.useState([]);
  const [aiLoading,      setAiLoading]      = React.useState(false);
  const [showTemplates,  setShowTemplates]  = React.useState(false);
  const [selectedWfIds, setSelectedWfIds] = React.useState(new Set());
  const toggleWfSelect = (id) => setSelectedWfIds(p => { const n=new Set(p); n.has(id)?n.delete(id):n.add(id); return n; });
  const clearWfSelect = () => setSelectedWfIds(new Set());
  const [showAiAssistant, setShowAiAssistant] = React.useState(false);
  const [showTemplateLib, setShowTemplateLib] = React.useState(false);
  const [activatingTpl,   setActivatingTpl]   = React.useState(null);

  // Seed built-in workflows into backend on first load if they don't exist yet
  const BUILTIN_SEEDS = [
    {
      id:"ads-sop", builtin_type:"system", enabled:true,
      name:"Daily Ads Data Availability Check",
      desc:"Full download failure runbook — detection through validation, refresh, and GDS copy jobs. Uses approval gates.",
      schedule:"manual",
      checks:[
        {name:"Amazon Ads Data Available", sql:"SELECT COUNT(*) FROM mws.report WHERE download_date=CURRENT_DATE AND status='processed'", pass_condition:"rows > 0", severity:"critical"},
        {name:"Stuck Copies", sql:"SELECT COUNT(*) FROM mws.report WHERE status='processed' AND copy_status!='REPLICATED' AND download_date>=CURRENT_DATE-1", pass_condition:"rows = 0", severity:"high"},
      ],
      tables:["mws.report"], agents:[], db_key:"default",
    },
  ];

  // Seed on mount — save built-ins to backend if not already there
  const seedBuiltins = async (existingIds) => {
    for (const seed of BUILTIN_SEEDS) {
      if (!existingIds.includes(seed.id)) {
        await fetch(`${API}/api/custom-workflows/save/v2`, {
          method:"POST", headers:{"Content-Type":"application/json"},
          body:JSON.stringify(seed)
        }).catch(()=>{});
      }
    }
  };

  const runBuiltin = async (wf) => {
    if (wf.id === "ads-sop") {
      // Always use the full SOP gate workflow for Ads SOP
      setSopRunning(true);
      try {
        const res  = await fetch(`${API}/api/workflow/ads-sop`, {method:"POST"});
        const data = await res.json();
        setSopResult(data);
      } catch(e) {}
      setSopRunning(false);
      return;
    }
    await runWf(wf);
  };

  const [aiSuggestError, setAiSuggestError] = React.useState(null);

  const getAiSuggestions = async () => {
    setAiLoading(true);
    setAiSuggestError(null);
    setAiSuggestions([]);
    try {
      const schema = dbSchema
        ? dbSchema.split(";").slice(0,8).join(";")
        : "mws.report(status,download_date,report_type,copy_status,account_id), mws.orders(amazon_order_id,asin,status,purchase_date,item_price,quantity,account_id), mws.inventory(asin,available,snapshot_date,account_id), mws.sales_and_traffic_by_date(sale_date,ordered_revenue,sessions,account_id), public.tbl_amzn_campaign_report(profile_id,report_date,impressions,clicks,spend,sales)";

      // Variety seeds — rotate through focus areas so each click gives different suggestions
      const FOCUS_AREAS = [
        "advertising performance anomalies and spend efficiency",
        "inventory health, stockouts and overstock detection",
        "order pipeline integrity and fulfillment issues",
        "data freshness and pipeline timing violations",
        "revenue trends, BSR correlation and sales velocity",
        "cross-table referential integrity and orphaned records",
        "campaign ROI, ACOS drift and keyword performance",
        "replication lag, copy job failures and GDS sync issues",
        "buy box percentage drops and competitor pricing signals",
        "seasonal pattern deviations and anomaly detection",
      ];
      const existingNames = workflows.map(w=>w.name).join(", ") || "none";
      const focusArea = FOCUS_AREAS[Math.floor(Math.random() * FOCUS_AREAS.length)];
      const seed = Math.random().toString(36).slice(2,6); // random 4-char seed for variety

      const res = await fetch(`${API}/api/ai/chat`, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          system:`You are a senior data engineering lead specialising in Amazon Seller analytics on Redshift.
Generate exactly 3 UNIQUE data quality workflow suggestions. Focus area this time: ${focusArea}.

Schema: ${schema}

IMPORTANT — do NOT suggest workflows similar to these already existing ones: ${existingNames}
Be creative and specific. Each suggestion must be meaningfully different from the others.
Seed: ${seed}

Rules:
- Each workflow: 2-3 checks
- SQL must SELECT actual suspect rows (not bare COUNT(*)), use only real schema columns
- Vary schedules: mix of hourly, daily, weekly
- No markdown, no explanation text outside JSON

Respond with ONLY this JSON array (no other text, no backticks):
[{"name":"string","desc":"string","schedule":"daily","icon":"emoji","tags":["string"],"checks":[{"name":"string","sql":"string","pass_condition":"rows = 0","severity":"critical|high|medium|low","explanation":"string"}]}]`,
          messages:[{role:"user",content:`Generate 3 fresh workflow suggestions focused on ${focusArea}. JSON array only.`}],
          max_tokens:1400,
          temperature:0.9
        })
      });

      if (!res.ok) {
        const err = await res.json().catch(()=>({}));
        setAiSuggestError(err.error || `Server error ${res.status}`);
        setAiLoading(false); return;
      }

      const data = await res.json();
      const raw  = (data?.content?.[0]?.text || "").trim();

      if (!raw) {
        setAiSuggestError("Empty response — check OPENAI_API_KEY on Railway");
        setAiLoading(false); return;
      }

      // Parse: strip markdown fences, find [ ... ]
      let arr = null;
      const stripped = raw.replace(/```json|```/gi,"").trim();
      try {
        const parsed = JSON.parse(stripped);
        arr = Array.isArray(parsed) ? parsed
            : Array.isArray(parsed.workflows) ? parsed.workflows
            : null;
      } catch(_) {
        const s = stripped.indexOf("["), e = stripped.lastIndexOf("]");
        if (s !== -1 && e > s) {
          try { arr = JSON.parse(stripped.slice(s, e+1)); } catch(_2) {}
        }
      }

      if (Array.isArray(arr) && arr.length > 0) {
        setAiSuggestions(arr);
      } else {
        setAiSuggestError(`Parse failed — raw: ${raw.slice(0,120)}`);
      }
    } catch(e) {
      setAiSuggestError(e.message || "Network error");
    }
    setAiLoading(false);
  };

  const applyTemplate = (tmpl) => {
    setEditing({...tmpl, id:""});
    setView("builder");
    setShowTemplates(false);
  };

  const TEMPLATES = [
    { name:"Null Check — Orders", desc:"Flag orders with missing ASINs or item prices",
      schedule:"every 30 min", checks:[
        {name:"Null ASIN in Orders", sql:"SELECT COUNT(*) FROM mws.orders WHERE asin IS NULL AND download_date=(SELECT MAX(download_date) FROM mws.orders)", pass_condition:"rows = 0", severity:"high"},
        {name:"Zero/Negative Price Shipped", sql:"SELECT COUNT(*) FROM mws.orders WHERE item_price<=0 AND order_status='Shipped' AND download_date=(SELECT MAX(download_date) FROM mws.orders)", pass_condition:"rows = 0", severity:"medium"},
      ]},
    { name:"Freshness Check — Report", desc:"Ensure mws.report has data from today",
      schedule:"every 30 min", checks:[
        {name:"Today's Data Present", sql:"SELECT COUNT(*) FROM mws.report WHERE download_date=CURRENT_DATE", pass_condition:"rows > 0", severity:"critical"},
        {name:"Failed Downloads", sql:"SELECT COUNT(*) FROM mws.report WHERE status='failed' AND download_date=CURRENT_DATE", pass_condition:"rows = 0", severity:"high"},
      ]},
    { name:"Replication Health", desc:"Monitor copy status for stuck records",
      schedule:"every 30 min", checks:[
        {name:"Stuck Copies", sql:"SELECT COUNT(*) FROM mws.report WHERE status='processed' AND (copy_status IS NULL OR copy_status='NOT_REPLICATED') AND download_date>=CURRENT_DATE-1", pass_condition:"rows = 0", severity:"high"},
        {name:"Not Replicated Today", sql:"SELECT COUNT(*) FROM mws.report WHERE copy_status!='REPLICATED' AND download_date=CURRENT_DATE", pass_condition:"rows = 0", severity:"medium"},
      ]},
    { name:"Inventory Integrity", desc:"Check for negative or missing inventory data",
      schedule:"every 1 hour", checks:[
        {name:"Negative Available Units", sql:"SELECT COUNT(*) FROM mws.inventory WHERE available<0 AND download_date=(SELECT MAX(download_date) FROM mws.inventory)", pass_condition:"rows = 0", severity:"high"},
        {name:"Out of Stock SKUs", sql:"SELECT COUNT(*) FROM mws.inventory WHERE available=0 AND download_date=(SELECT MAX(download_date) FROM mws.inventory)", pass_condition:"rows = 0", severity:"medium"},
      ]},
  ];

  if (view==="builder") return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%", overflow:"hidden" }}>
      {saveError && (
        <div style={{ padding:"10px 20px", background:`${T.red}08`, borderBottom:`1px solid ${T.red}30`,
          fontSize:12, color:T.red, flexShrink:0 }}>
          ✗ Save failed: {saveError} —{" "}
          <button onClick={()=>setSaveError(null)} style={{background:"none",border:"none",cursor:"pointer",color:T.red,textDecoration:"underline"}}>dismiss</button>
        </div>
      )}
      <WorkflowBuilder
        initial={editingWf}
        dbSchema={dbSchema}
        onSave={saveWf}
        onCancel={()=>{ setView("list"); setEditing(null); setSaveError(null); }}
      />
    </div>
  );

  if (view==="detail" && detailWf) return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%", overflow:"hidden" }}>
      <WorkflowDetail
        wf={detailWf}
        history={runHistory.filter(r=>r.workflow_id===detailWf.id).slice(0,10)}
        liveRun={liveRun}
        onBack={()=>{ setView("list"); setLiveRun(null); }}
        onEdit={()=>{ setEditing(detailWf); setView("builder"); }}
        onRun={()=>runWf(detailWf)}
        running={!!running[detailWf.id]}
      />
    </div>
  );

  if (view==="library") return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%", overflow:"hidden" }}>
      <div style={{ padding:"10px 20px", borderBottom:`1px solid ${T.border}`, flexShrink:0 }}>
        <Btn onClick={()=>setView("list")} variant="ghost" size="sm">← Workflows</Btn>
      </div>
      <CheckLibrary standalone={true} onUse={(chk)=>{
        setEditing(p => p ? {...p, checks:[...(p.checks||[]),{...chk,id:Date.now().toString(36)}]} : {name:"",desc:"",schedule:"every 30 min",enabled:true,checks:[{...chk,id:Date.now().toString(36)}],tables:[],db_key:"default",slack_channel:""});
        setView("builder");
      }}/>
    </div>
  );

  if (view==="sop") return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%", overflow:"hidden" }}>
      <div style={{ padding:"10px 20px", borderBottom:`1px solid #E2E8F0`,
        flexShrink:0, display:"flex", alignItems:"center", gap:10 }}>
        <Btn onClick={()=>setView("list")} variant="ghost" size="sm">← Workflows</Btn>
        <span style={{ fontSize:14, fontWeight:700, color:T.text }}>
          Daily Ads Data Availability Check
        </span>
      </div>
      <div style={{ flex:1, overflowY:"auto" }}>
        <AdsSopTab/>
      </div>
    </div>
  );

  if (view==="runs") return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%", overflow:"hidden" }}>
      <AllRunsView
        history={runHistory}
        workflows={workflows}
        onBack={()=>setView("list")}
        onOpenWf={(wf)=>{ setDetail(wf); setView("detail"); }}
      />
    </div>
  );

  // ── List view ─────────────────────────────────────────────────────────────
  const recentRuns = runHistory.slice(0,20);

  return (
    <div style={{ display:"flex", minHeight:"100%" }}>
    {/* Main content */}
    <div style={{ flex:1, padding:"24px 28px", maxWidth: showAiAssistant ? 700 : 1100 }}>

      {/* Header */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:20 }}>
        <div>
          <div style={{ fontSize:24, fontWeight:800, color:T.text, letterSpacing:"-0.03em" }}>Workflows</div>
          <div style={{ fontSize:12, color:T.muted, marginTop:2 }}>
            Custom workflows · {workflows.length} configured
          </div>
        </div>
        <div style={{ display:"flex", gap:8 }}>
          {runHistory.length>0 && (
            <Btn onClick={()=>setView("runs")} variant="ghost" size="sm">
              <Clock size={11}/> All Runs ({runHistory.length})
            </Btn>
          )}
          <Btn onClick={()=>setView("library")} variant="ghost" size="sm">
            📚 Library
          </Btn>
          <Btn onClick={()=>setShowTemplates(p=>!p)} variant="ghost" size="sm">
            📋 Templates
          </Btn>
          <Btn onClick={()=>setShowAiAssistant(p=>!p)} variant="ghost" size="sm"
            style={{ border:`1px solid ${T.accent}30`, color:T.accent }}>
            🤖 AI Assistant
          </Btn>
          <Btn onClick={()=>{ setEditing(null); setView("builder"); }}
            style={{ background:`linear-gradient(135deg,${T.accent},${T.purple})`, color:"white", border:"none" }}>
            <Plus size={12}/> New Workflow
          </Btn>
        </div>
      </div>

      {/* ── Cross-workflow correlation banner ── */}
      {(() => {
        if (runHistory.length < 2) return null;
        const windowMs = 15 * 60 * 1000; // 15-minute window
        const now = Date.now();
        // Group recent failures within 15-min windows
        const recentFails = runHistory
          .filter(r => r.status !== "clean" && r.status !== "pass" && r.started_at)
          .filter(r => (now - new Date(r.started_at).getTime()) < 2 * 60 * 60 * 1000) // last 2h
          .slice(0, 20);
        if (recentFails.length < 2) return null;
        // Find largest cluster within 15 min
        let bestCluster = [];
        recentFails.forEach(anchor => {
          const t = new Date(anchor.started_at).getTime();
          const cluster = recentFails.filter(r => Math.abs(new Date(r.started_at).getTime() - t) <= windowMs);
          if (cluster.length > bestCluster.length) bestCluster = cluster;
        });
        if (bestCluster.length < 2) return null;
        const names = [...new Set(bestCluster.map(r => r.workflow_name || r.name || "Unknown"))];
        const earliest = bestCluster.map(r=>new Date(r.started_at)).sort((a,b)=>a-b)[0];
        const minsAgo = Math.round((now - earliest.getTime()) / 60000);
        return (
          <div style={{ marginBottom:16, padding:"10px 14px", borderRadius:10,
            background:"#FFF7ED", border:"1px solid #FED7AA",
            display:"flex", gap:10, alignItems:"flex-start" }}>
            <span style={{fontSize:16, flexShrink:0}}>🔗</span>
            <div style={{flex:1}}>
              <div style={{fontSize:12, fontWeight:700, color:"#C2410C", marginBottom:2}}>
                {bestCluster.length} workflows failed within 15 minutes — possible shared root cause
              </div>
              <div style={{fontSize:11, color:"#9A3412"}}>
                {names.slice(0,4).join(", ")}{names.length>4?` +${names.length-4} more`:""} · {minsAgo < 60 ? `${minsAgo}m ago` : `${Math.round(minsAgo/60)}h ago`}
              </div>
            </div>
            <button onClick={()=>{
                sessionStorage.setItem("wz_agent_nudge", `Why did ${names.slice(0,3).join(", ")} all fail around the same time?`);
                window.dispatchEvent(new CustomEvent("wz_open_agent"));
              }}
              style={{fontSize:10, padding:"3px 10px", borderRadius:6,
                background:"#FED7AA", border:"1px solid #FDBA74",
                color:"#92400E", cursor:"pointer", fontFamily:"inherit", fontWeight:600, flexShrink:0}}>
              Investigate →
            </button>
          </div>
        );
      })()}

      {/* Recent activity strip */}
      {recentRuns.length > 0 && (
        <div style={{ marginBottom:20, padding:"12px 16px", borderRadius:10,
          background:T.surface, border:`1px solid ${T.border}` }}>
          <div style={{ fontSize:10, fontWeight:700, color:T.muted, textTransform:"uppercase",
            letterSpacing:"0.06em", marginBottom:8 }}>Recent Runs</div>
          <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
            {recentRuns.slice(0,15).map(run=>(
              <div key={run.run_id}
                onClick={()=>{ const wf=workflows.find(w=>w.id===run.workflow_id); if(wf){setDetail(wf);setLiveRun(run);setView("detail");} }}
                style={{ display:"flex", alignItems:"center", gap:6, padding:"4px 10px",
                  borderRadius:99, cursor:"pointer", fontSize:10,
                  background:run.status==="clean"?`${T.green}10`:`${T.red}10`,
                  border:`1px solid ${run.status==="clean"?T.green:T.red}25` }}>
                <div style={{ width:6, height:6, borderRadius:"50%",
                  background:run.status==="clean"?T.green:T.red }}/>
                <span style={{ fontWeight:600, color:T.text2 }}>{run.workflow_name?.slice(0,18)||"Run"}</span>
                <span style={{ color:T.dim }}>{run.started_at?.slice(11,16)}</span>
                {run.failed > 0 && <span style={{ color:T.red, fontWeight:700 }}>{run.failed} fail</span>}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── BUILT-IN WORKFLOWS + TEMPLATE LIBRARY ─────────────────────────── */}
      {(() => {
        const builtins = BUILTIN_WFS;
        return (
          <div style={{ marginBottom:20 }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10 }}>
              <div style={{ fontSize:11, fontWeight:700, color:T.muted, textTransform:"uppercase",
                letterSpacing:"0.06em" }}>Built-in Workflows</div>
              <Btn size="sm" variant="ghost" onClick={()=>setShowTemplateLib(p=>!p)}
                style={{ fontSize:10, color:T.purple, borderColor:`${T.purple}30` }}>
                {showTemplateLib?"Hide":"＋ Add from Library"}
              </Btn>
            </div>

            {/* Template Library panel */}
            {showTemplateLib && (
              <div style={{ marginBottom:14, padding:"16px 18px", borderRadius:10,
                border:`1px solid ${T.purple}30`, background:`${T.purple}04` }}>
                <div style={{ fontSize:12, fontWeight:700, color:T.purple, marginBottom:12 }}>
                  📚 Built-in Workflow Templates
                </div>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:10 }}>
                  {BUILTIN_TEMPLATES.map(tpl=>{
                    const isActive = workflows.some(w=>w.id===tpl.id) ||
                                     builtins.some(b=>b.id===tpl.id);
                    const isActivating = activatingTpl===tpl.id;
                    return (
                      <div key={tpl.id} style={{ padding:"14px 16px", borderRadius:9,
                        border:`1px solid ${isActive?tpl.color+"40":T.border}`,
                        background:isActive?`${tpl.color}06`:T.card }}>
                        <div style={{ fontSize:20, marginBottom:6 }}>{tpl.icon}</div>
                        <div style={{ fontSize:12, fontWeight:700, color:T.text, marginBottom:4 }}>
                          {tpl.name}
                        </div>
                        <div style={{ fontSize:10, color:T.muted, lineHeight:1.5, marginBottom:8 }}>
                          {tpl.desc}
                        </div>
                        <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginBottom:10 }}>
                          {tpl.tags.map(tag=>(
                            <span key={tag} style={{ fontSize:9, padding:"2px 7px", borderRadius:99,
                              background:`${tpl.color}12`, color:tpl.color, fontWeight:600 }}>
                              {tag}
                            </span>
                          ))}
                        </div>
                        <div style={{ fontSize:9, color:T.dim, marginBottom:10 }}>
                          {tpl.phases.length} phases · {tpl.gates.length} approval gates · {tpl.detection_checks.length} checks
                        </div>
                        {isActive
                          ? <Badge label="Active" color={tpl.color}/>
                          : <Btn size="sm" onClick={async()=>{
                              setActivatingTpl(tpl.id);
                              // Create workflow from template
                              const wf = {
                                id: tpl.id,
                                name: tpl.name,
                                desc: tpl.desc,
                                schedule: "daily",
                                enabled: true,
                                checks: tpl.detection_checks.map((c,i)=>({...c, id:`${tpl.id}_c${i}`})),
                                tables: [], db_key:"default", slack_channel:"",
                                builtin_type:"template", template_id:tpl.id,
                                color: tpl.color,
                              };
                              await fetch(`${API}/api/custom-workflows/save/v2`,{
                                method:"POST", headers:{"Content-Type":"application/json"},
                                body:JSON.stringify(wf)
                              }).catch(()=>{});
                              setWfs(p=>[...p.filter(w=>w.id!==tpl.id), wf]);
                              setActivatingTpl(null);
                              setShowTemplateLib(false);
                            }}
                            disabled={isActivating}
                            style={{ background:tpl.color, color:"white", border:"none", fontSize:10 }}>
                            {isActivating?<Spinner size={9} color="white"/>:null}
                            {isActivating?"Adding…":"＋ Add Workflow"}
                          </Btn>
                        }
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
              {builtins.map(wf=>{
                const accentColor = wf.id==="ads-sop" ? T.orange : T.accent;
                const isRunning   = !!running[wf.id] || (wf.id==="ads-sop"&&sopRunning);
                const wfRuns      = runHistory.filter(r=>r.workflow_id===wf.id);
                const lastRun     = wfRuns[0];
                return (
                  <div key={wf.id} style={{ background:T.card, border:`1px solid ${T.border}`,
                    borderLeft:`3px solid ${accentColor}`, borderRadius:10, padding:"14px 16px" }}>
                    <div style={{ display:"flex", alignItems:"flex-start", gap:10, marginBottom:6 }}>
                      <div style={{ flex:1 }}>
                        <div style={{ fontSize:13, fontWeight:700, color:T.text }}>{wf.name}</div>
                        <div style={{ fontSize:11, color:T.muted, marginTop:2, lineHeight:1.4 }}>{wf.desc}</div>
                      </div>
                    </div>
                    {/* Schedule + checks summary */}
                    <div style={{ display:"flex", gap:6, alignItems:"center", marginBottom:8, flexWrap:"wrap" }}>
                      <Badge label={wf.schedule||"manual"} color={accentColor}/>
                      {(wf.checks||[]).length > 0 && (
                        <span style={{ fontSize:10, color:T.muted }}>
                          {wf.checks.length} check{wf.checks.length!==1?"s":""}
                        </span>
                      )}
                      {lastRun && (
                        <span style={{ fontSize:10,
                          color:lastRun.status==="clean"?T.green:T.red }}>
                          · last: {lastRun.status==="clean"?"✓":"✗"} {lastRun.started_at?.slice(11,16)}
                        </span>
                      )}
                      {/* Sparkline — last 10 runs */}
                      {wfRuns.length > 1 && (
                        <div style={{ display:"flex", gap:2, alignItems:"center", marginLeft:4 }}>
                          {wfRuns.slice(0,10).reverse().map((r,i)=>(
                            <div key={i} style={{ width:6, height:6, borderRadius:"50%",
                              background:r.status==="clean"?T.green:T.red,
                              opacity: 0.4 + (i/10)*0.6,
                              title:r.started_at?.slice(0,16) }}/>
                          ))}
                        </div>
                      )}
                    </div>
                    <div style={{ display:"flex", gap:7, flexWrap:"wrap" }}>
                      <Btn onClick={()=>{ runBuiltin(wf); if(wf.id==="ads-sop") setView("sop"); }} disabled={isRunning} size="sm"
                        style={{ background:isRunning?T.border:accentColor, color:"white", border:"none" }}>
                        {isRunning?<Spinner size={10} color="white"/>:<Play size={10}/>}
                        {wf.id==="ads-sop"?"Start Check":"Run Now"}
                      </Btn>
                      {wf.id==="ads-sop" && (
                        <Btn size="sm" variant="ghost" onClick={()=>setView("sop")}>
                          Open Check
                        </Btn>
                      )}
                      <Btn onClick={()=>{
                          const backendWf = workflows.find(w=>w.id===wf.id);
                          setEditing(backendWf ? {...wf,...backendWf} : wf);
                          setView("builder");
                        }}
                        size="sm" variant="ghost">✏ Edit</Btn>
                      <Btn onClick={()=>{ setDetail(wf); setLiveRun(null); setView("detail"); }}
                        size="sm" variant="ghost"><Eye size={10}/> History</Btn>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* ── AI SUGGESTIONS + TEMPLATES ──────────────────────────────────────── */}
      <div style={{ marginBottom:20 }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10 }}>
          <div style={{ fontSize:11, fontWeight:700, color:T.muted, textTransform:"uppercase",
            letterSpacing:"0.06em" }}>Quick Start Templates</div>
          <div style={{ display:"flex", gap:7 }}>
            <Btn onClick={getAiSuggestions} disabled={aiLoading} size="sm" variant="ghost"
              style={{ color:T.purple, borderColor:`${T.purple}30` }}>
              {aiLoading?<Spinner size={10}/>:<Zap size={10}/>}
              {aiLoading?" Generating…":" AI Suggest"}
            </Btn>
            <Btn onClick={()=>setShowTemplates(p=>!p)} size="sm" variant="ghost">
              {showTemplates?"Hide":"Show"} Templates
            </Btn>
          </div>
        </div>

        {/* AI error */}
        {aiSuggestError && (
          <div style={{ padding:"8px 12px", borderRadius:8, marginBottom:8,
            background:`${T.red}08`, border:`1px solid ${T.red}25`,
            fontSize:11, color:T.red, display:"flex", justifyContent:"space-between",
            alignItems:"center" }}>
            <span>✗ {aiSuggestError}</span>
            <button onClick={()=>setAiSuggestError(null)}
              style={{ background:"none", border:"none", cursor:"pointer",
                color:T.red, fontSize:14 }}>×</button>
          </div>
        )}

        {/* AI suggestions */}
        {aiSuggestions.length > 0 && (
          <div style={{ marginBottom:16 }}>
            <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
              <div style={{ width:20, height:20, borderRadius:5,
                background:`linear-gradient(135deg,${T.accent},${T.purple})`,
                display:"flex", alignItems:"center", justifyContent:"center",
                fontSize:11 }}>✨</div>
              <span style={{ fontSize:11, fontWeight:700, color:T.text }}>
                AI-Generated Suggestions
              </span>
              <span style={{ fontSize:10, color:T.muted }}>
                — click any to load into the workflow builder
              </span>
              <button onClick={()=>setAiSuggestions([])}
                style={{ marginLeft:"auto", background:"none", border:"none",
                  cursor:"pointer", color:T.dim, fontSize:11 }}>✕ Clear</button>
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
              {aiSuggestions.map((s,i)=>(
                <div key={s.name||i}
                  style={{ padding:"14px 16px", borderRadius:10, cursor:"pointer",
                    background:T.surface,
                    border:`1px solid ${T.border}`,
                    transition:"all 0.15s",
                    position:"relative", overflow:"hidden" }}
                  onMouseEnter={e=>{
                    e.currentTarget.style.borderColor=T.accent;
                    e.currentTarget.style.boxShadow=`0 4px 16px ${T.accent}18`;
                  }}
                  onMouseLeave={e=>{
                    e.currentTarget.style.borderColor=T.border;
                    e.currentTarget.style.boxShadow="none";
                  }}
                  onClick={()=>applyTemplate(s)}>
                  {/* Accent bar */}
                  <div style={{ position:"absolute", top:0, left:0, right:0, height:3,
                    background:`linear-gradient(90deg,${T.accent},${T.purple})`,
                    borderRadius:"10px 10px 0 0" }}/>

                  {/* Header */}
                  <div style={{ display:"flex", alignItems:"flex-start", gap:8, marginBottom:8 }}>
                    <span style={{ fontSize:20, flexShrink:0 }}>{s.icon||"📋"}</span>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:12, fontWeight:700, color:T.text,
                        marginBottom:2, lineHeight:1.3 }}>{s.name}</div>
                      <div style={{ fontSize:10, color:T.muted, lineHeight:1.4 }}>{s.desc}</div>
                    </div>
                  </div>

                  {/* Tags + schedule */}
                  <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginBottom:8 }}>
                    {s.schedule && (
                      <span style={{ fontSize:9, padding:"2px 7px", borderRadius:4,
                        background:`${T.accent}10`, color:T.accent, fontWeight:600 }}>
                        ⏱ {s.schedule}
                      </span>
                    )}
                    {(s.tags||[]).map(tag=>(
                      <span key={tag} style={{ fontSize:9, padding:"2px 7px", borderRadius:4,
                        background:T.border, color:T.muted }}>
                        {tag}
                      </span>
                    ))}
                  </div>

                  {/* Checks preview */}
                  <div style={{ display:"flex", flexDirection:"column", gap:4, marginBottom:10 }}>
                    {(s.checks||[]).map((c,j)=>(
                      <div key={j} style={{ display:"flex", alignItems:"flex-start", gap:6 }}>
                        <span style={{ fontSize:9, marginTop:1, flexShrink:0,
                          color:{critical:T.red,high:T.orange,medium:"#F59E0B",low:T.cyan}[c.severity]||T.muted }}>
                          {c.severity==="critical"?"🔴":c.severity==="high"?"🟠":c.severity==="medium"?"🟡":"🟢"}
                        </span>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontSize:10, fontWeight:600, color:T.text2 }}>{c.name}</div>
                          {c.explanation && (
                            <div style={{ fontSize:9, color:T.dim, marginTop:1 }}>{c.explanation}</div>
                          )}
                          <div style={{ fontSize:9, color:T.muted, fontFamily:"monospace",
                            marginTop:2, whiteSpace:"nowrap", overflow:"hidden",
                            textOverflow:"ellipsis", maxWidth:"100%" }}>
                            {(c.sql||"").slice(0,60)}{c.sql?.length>60?"…":""}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>

                  {/* CTA */}
                  <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                    <span style={{ fontSize:9, color:T.dim }}>
                      {(s.checks||[]).length} check{(s.checks||[]).length!==1?"s":""}
                    </span>
                    <span style={{ fontSize:10, fontWeight:700, color:T.accent,
                      display:"flex", alignItems:"center", gap:4 }}>
                      Use this <ArrowRight size={10}/>
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Templates */}
        {showTemplates && (
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
            {TEMPLATES.map((t,i)=>(
              <div key={t.name||i} style={{ padding:"12px 14px", borderRadius:8,
                background:T.surface, border:`1px solid ${T.border}` }}>
                <div style={{ fontSize:12, fontWeight:700, color:T.text, marginBottom:2 }}>{t.name}</div>
                <div style={{ fontSize:11, color:T.muted, marginBottom:8 }}>{t.desc}</div>
                <div style={{ display:"flex", gap:5, marginBottom:8, flexWrap:"wrap" }}>
                  {t.checks.map((c,j)=>(
                    <span key={j} style={{ fontSize:9, padding:"2px 7px", borderRadius:4,
                      background:`${T.accent}08`, color:T.accent }}>{c.name}</span>
                  ))}
                </div>
                <Btn size="sm" variant="ghost" onClick={()=>applyTemplate(t)}>
                  <Plus size={9}/> Use template
                </Btn>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* ── CUSTOM WORKFLOWS ────────────────────────────────────────────────── */}
      <div>
        <div style={{ fontSize:11, fontWeight:700, color:T.muted, textTransform:"uppercase",
          letterSpacing:"0.06em", marginBottom:10 }}>Custom Workflows ({workflows.length})</div>
        {workflows.length===0 ? (
          <div style={{ textAlign:"center", padding:"32px 0",
            border:`1px dashed ${T.border}`, borderRadius:10 }}>
            <GitBranch size={32} color={T.border} style={{ margin:"0 auto 10px", display:"block" }}/>
            <div style={{ fontSize:13, fontWeight:600, color:T.text, marginBottom:4 }}>No custom workflows yet</div>
            <div style={{ fontSize:11, color:T.muted, marginBottom:14 }}>
              Add SQL checks that run on your schedule
            </div>
            <Btn onClick={()=>setView("builder")} size="sm"
              style={{ background:`linear-gradient(135deg,${T.accent},${T.purple})`, color:"white", border:"none" }}>
              <Plus size={11}/> New Workflow
            </Btn>
          </div>
        ) : (
          <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
            {workflows.map(wf=>{
            const wfRuns   = runHistory.filter(r=>r.workflow_id===wf.id);
            const lastRun  = wfRuns[0];
            const isRunning = !!running[wf.id];
            const isWfSel  = selectedWfIds.has(wf.id);
            const passRate  = wfRuns.slice(0,10).length > 0
              ? Math.round(wfRuns.slice(0,10).filter(r=>r.status==="clean").length/Math.min(wfRuns.length,10)*100)
              : null;
            const sparkData = wfRuns.slice(0,20).reverse();
            // Failure pattern: detect day-of-week correlation (zero tokens)
            const failurePattern = (() => {
              if (wfRuns.length < 6) return null;
              const dayFails = {};
              wfRuns.slice(0,20).forEach(r => {
                const day = new Date(r.started_at).toLocaleDateString("en",{weekday:"short"});
                if (!dayFails[day]) dayFails[day] = {fail:0,total:0};
                dayFails[day].total++;
                if (r.status!=="clean") dayFails[day].fail++;
              });
              const worst = Object.entries(dayFails)
                .filter(([,v])=>v.total>=2)
                .map(([day,v])=>({day,rate:v.fail/v.total}))
                .sort((a,b)=>b.rate-a.rate)[0];
              if (worst && worst.rate >= 0.6)
                return `⚠ Often fails on ${worst.day}s`;
              return null;
            })();

            return (
              <div key={wf.id} style={{ background:T.card,
                border:`1px solid ${isWfSel ? T.accent : T.border}`,
                borderRadius:12, padding:"16px 20px",
                borderLeft:`3px solid ${isWfSel ? T.accent : wf.enabled!==false?T.accent:T.border}`,
                background: isWfSel ? `${T.accent}05` : T.card,
                boxShadow:"0 1px 4px rgba(0,0,0,0.06)" }}>
                <div style={{ display:"flex", alignItems:"flex-start", gap:14 }}>
                  <input type="checkbox" checked={isWfSel}
                    onChange={()=>toggleWfSelect(wf.id)}
                    style={{ marginTop:4, cursor:"pointer", accentColor:T.accent, flexShrink:0 }}
                    onClick={e=>e.stopPropagation()}/>

                  {/* Left: info */}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
                      <div style={{ fontSize:14, fontWeight:700, color:T.text }}>{wf.name}</div>
                      <Badge label={wf.schedule||"manual"} color={T.accent}/>
                      {wf.enabled===false && <Badge label="paused" color={T.muted}/>}
                      {isRunning && <div style={{ display:"flex", alignItems:"center", gap:4, fontSize:10, color:T.accent }}><Spinner size={9}/> Running…</div>}
                    </div>
                    {wf.desc && <div style={{ fontSize:11, color:T.muted, marginBottom:8 }}>{wf.desc}</div>}

                    {/* Check pills */}
                    <div style={{ display:"flex", gap:5, flexWrap:"wrap", marginBottom:8 }}>
                      {(wf.checks||[]).slice(0,6).map(chk=>(
                        <span key={chk.id||chk.name} style={{ fontSize:10, padding:"2px 8px",
                          borderRadius:4, background:`${T.accent}08`,
                          border:`1px solid ${T.accent}20`, color:T.accent }}>
                          {chk.name}
                        </span>
                      ))}
                      {(wf.checks||[]).length > 6 && (
                        <span style={{ fontSize:10, color:T.dim }}>+{wf.checks.length-6} more</span>
                      )}
                      {(!wf.checks || wf.checks.length===0) && (
                        <span style={{ fontSize:10, color:T.dim, fontStyle:"italic" }}>No checks configured</span>
                      )}
                    </div>

                    {/* Stats row */}
                    <div style={{ display:"flex", gap:16, alignItems:"center" }}>
                      {lastRun && (
                        <span style={{ fontSize:10, color:T.muted }}>
                          Last run: {lastRun.started_at?.slice(0,16)?.replace("T"," ")}
                          {" · "}
                          <span style={{ color:lastRun.status==="clean"?T.green:T.red, fontWeight:600 }}>
                            {lastRun.status==="clean"?"✓ clean":`${lastRun.failed} failed`}
                          </span>
                        </span>
                      )}
                      {passRate !== null && (
                        <span style={{ fontSize:10, color:T.muted }}>
                          Pass rate: <span style={{ fontWeight:700, color:passRate>=80?T.green:passRate>=50?T.orange:T.red }}>{passRate}%</span>
                        </span>
                      )}
                      {passRate !== null && (
                        <span style={{ fontSize:9, padding:"1px 6px", borderRadius:4, fontWeight:700,
                          background: passRate>=90?`${T.green}15`:passRate>=70?`#F59E0B18`:`${T.red}12`,
                          color: passRate>=90?T.green:passRate>=70?"#F59E0B":T.red }}>
                          {passRate>=90?"🟢 Healthy":passRate>=70?"🟡 Degrading":"🔴 Critical"}
                        </span>
                      )}
                      {wf.run_count > 0 && <span style={{ fontSize:10, color:T.dim }}>{wf.run_count} runs</span>}
                      {failurePattern && (
                        <span style={{ fontSize:9, color:"#F59E0B", fontWeight:600 }}>
                          {failurePattern}
                        </span>
                      )}
                    </div>

                    {/* Mini sparkline of last 20 runs */}
                    {sparkData.length > 1 && (
                      <div style={{ display:"flex", gap:2, marginTop:8, alignItems:"flex-end" }}>
                        {sparkData.map((r,i)=>(
                          <div key={r.run_id||i} title={`${r.started_at?.slice(0,16)} — ${r.status}`}
                            style={{ width:8, height:r.status==="clean"?12:20, borderRadius:2,
                              background:r.status==="clean"?T.green:T.red, opacity:0.7,
                              flexShrink:0 }}/>
                        ))}
                      </div>
                    )}
                  </div>

                  {/* Right: actions */}
                  <div style={{ display:"flex", flexDirection:"column", gap:6, flexShrink:0 }}>
                    <Btn onClick={()=>runWf(wf)} disabled={isRunning} size="sm"
                      style={{ background:`linear-gradient(135deg,${T.accent},${T.purple})`,
                        color:"white", border:"none" }}>
                      {isRunning?<Spinner size={10} color="white"/>:<Play size={10}/>} Run
                    </Btn>
                    <Btn onClick={()=>{ setDetail(wf); setLiveRun(null); setView("detail"); }}
                      size="sm" variant="ghost"><Eye size={10}/> History</Btn>
                    <Btn onClick={()=>{ setEditing(wf); setView("builder"); }}
                      size="sm" variant="ghost">✏ Edit</Btn>
                    <Btn onClick={()=>toggleEnabled(wf)} size="sm" variant="muted">
                      {wf.enabled===false?"▶ Enable":"⏸ Pause"}
                    </Btn>
                    <Btn onClick={()=>deleteWf(wf.id)} size="sm" variant="muted">
                      <Trash2 size={10}/>
                    </Btn>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
      </div>
    </div>

    {/* Undo delete toasts */}
    {undoQueue.length > 0 && (
      <div style={{ position:"fixed", bottom:80, left:"50%", transform:"translateX(-50%)",
        zIndex:9999, display:"flex", flexDirection:"column", gap:8 }}>
        {undoQueue.map(u=>(
          <div key={u.id} style={{ display:"flex", alignItems:"center", gap:12,
            padding:"10px 16px", borderRadius:10, background:T.card,
            border:`1px solid ${T.border}`, boxShadow:"0 4px 20px rgba(0,0,0,0.15)",
            fontSize:12 }}>
            <span style={{ color:T.text }}>"{u.wf.name}" deleted</span>
            <button onClick={()=>undoDelete(u.id)}
              style={{ background:"none", border:`1px solid ${T.accent}`,
                borderRadius:6, padding:"3px 10px", cursor:"pointer",
                color:T.accent, fontWeight:700, fontSize:11 }}>
              Undo
            </button>
          </div>
        ))}
      </div>
    )}

    {/* AI Assistant panel */}
    {showAiAssistant && (
      <div style={{ width:400, flexShrink:0, height:"100%", display:"flex", flexDirection:"column" }}>
        <AiWorkflowAssistant
          workflows={workflows}
          dbSchema={dbSchema}
          onSave={saveWf}
          onDelete={deleteWf}
          onRun={runWf}
          onClose={()=>setShowAiAssistant(false)}
          T={T}
        />
      </div>
    )}
    </div>
  );
}

// ── WorkflowDetail — runs history + drill-down for one workflow ───────────────
function WorkflowDetail({ wf, history, liveRun, onBack, onEdit, onRun, running }) {
  const T = useT();
  const [selectedRun, setSelectedRun] = React.useState(liveRun || history[0] || null);
  const [compareRun,  setCompareRun]  = React.useState(null); // run to compare against
  const [showDiff,    setShowDiff]    = React.useState(false);

  React.useEffect(() => {
    if (liveRun) setSelectedRun(liveRun);
  }, [liveRun]);

  const fmt = (iso) => iso?.slice(0,16)?.replace("T"," ") || "—";
  const dur = (ms) => ms < 1000 ? `${ms}ms` : `${(ms/1000).toFixed(1)}s`;

  return (
    <div style={{ display:"flex", flex:1, overflow:"hidden" }}>

      {/* Left: run list */}
      <div style={{ width:280, flexShrink:0, borderRight:`1px solid ${T.border}`,
        display:"flex", flexDirection:"column", overflow:"hidden" }}>
        <div style={{ padding:"14px 16px", borderBottom:`1px solid ${T.border}`, flexShrink:0 }}>
          <Btn onClick={onBack} variant="ghost" size="sm" style={{ marginBottom:8 }}>← Workflows</Btn>
          <div style={{ fontSize:14, fontWeight:700, color:T.text }}>{wf.name}</div>
          <div style={{ fontSize:10, color:T.muted, marginTop:2 }}>{wf.schedule}</div>
          <div style={{ display:"flex", gap:6, marginTop:10 }}>
            <Btn onClick={onRun} disabled={running} size="sm"
              style={{ background:`linear-gradient(135deg,${T.accent},${T.purple})`,
                color:"white", border:"none", flex:1, justifyContent:"center" }}>
              {running?<Spinner size={10} color="white"/>:<Play size={10}/>} Run now
            </Btn>
            <Btn onClick={onEdit} size="sm" variant="ghost">✏</Btn>
          </div>
          {history.length > 0 && (
            <Btn size="sm" variant="ghost" style={{ marginTop:6, width:"100%",
              fontSize:10, justifyContent:"center", color:T.accent }}
              onClick={()=>{
                window.location.hash=`results/${history[0].run_id}/${(history[0].check_results||[])[0]?.id||(history[0].check_results||[])[0]?.name||''}`;
                if(typeof navigateTo==="function") navigateTo("results");
              }}>
              📊 View in Results
            </Btn>
          )}
        </div>

        {/* Run list */}
        <div style={{ flex:1, overflowY:"auto" }}>
          {history.length===0 ? (
            <div style={{ padding:"20px 16px", fontSize:11, color:T.dim, textAlign:"center" }}>
              {running
                ? <><Spinner size={12}/><span style={{marginLeft:6}}>Running checks…</span></>
                : "No runs yet — click Run now"}
            </div>
          ) : (
            history.map(run=>(
              <div key={run.run_id}
                onClick={()=>setSelectedRun(run)}
                style={{ padding:"10px 16px", borderBottom:`1px solid ${T.border}`,
                  cursor:"pointer", borderLeft:`3px solid ${run.status==="clean"?T.green:T.red}`,
                  background:selectedRun?.run_id===run.run_id?`${T.accent}06`:"transparent",
                  position:"relative" }}>
                <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between",
                  marginBottom:3 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:5 }}>
                    <div style={{ width:7, height:7, borderRadius:"50%", flexShrink:0,
                      background:run.status==="clean"?T.green:T.red }}/>
                    <span style={{ fontSize:11, fontWeight:600, color:T.text }}>
                      {run.status==="clean"?"Clean":`${run.failed||0} Failed`}
                    </span>
                  </div>
                  <span style={{ fontSize:9, color:T.dim }}>
                    {run.triggered_by==="cron"?"⏰":"▶"} {fmt(run.started_at).slice(5)}
                  </span>
                </div>
                <div style={{ fontSize:10, color:T.muted }}>
                  {run.passed||0}/{run.total_checks||0} checks passed
                  {run.duration_ms && ` · ${dur(run.duration_ms)}`}
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Right: run detail */}
      <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden", minWidth:0 }}>
        {!selectedRun ? (
          <div style={{ display:"flex", alignItems:"center", justifyContent:"center",
            flex:1, color:T.dim, fontSize:13, flexDirection:"column", gap:10 }}>
            {running
              ? <><Spinner size={20}/><span style={{fontSize:12}}>Running checks…</span></>
              : "Select a run to see results"}
          </div>
        ) : (
          <>
            {history.length > 1 && (
              <div style={{ padding:"8px 20px", borderBottom:`1px solid ${T.border}`,
                display:"flex", alignItems:"center", gap:8, flexShrink:0, background:T.surface }}>
                <span style={{ fontSize:11, color:T.muted }}>Compare with:</span>
                <select onChange={e=>{
                    const r = history.find(h=>h.run_id===e.target.value);
                    setCompareRun(r||null);
                  }}
                  defaultValue=""
                  style={{ padding:"3px 8px", borderRadius:6, fontSize:11,
                    border:`1px solid ${T.border}`, background:T.card,
                    color:T.text, outline:"none" }}>
                  <option value="">— select run —</option>
                  {history.filter(r=>r.run_id!==selectedRun.run_id).map(r=>(
                    <option key={r.run_id} value={r.run_id}>
                      {r.started_at?.slice(0,16)?.replace("T"," ")} · {r.status==="clean"?"✓":"✗"}
                    </option>
                  ))}
                </select>
                {compareRun && (
                  <Btn size="sm" onClick={()=>setShowDiff(true)}
                    style={{ background:`${T.accent}10`, color:T.accent, border:`1px solid ${T.accent}30` }}>
                    View Diff
                  </Btn>
                )}
              </div>
            )}
            <div style={{ flex:1, overflowY:"auto", padding:"20px 24px" }}>
              <RunDetail run={selectedRun} T={T} dur={dur} fmt={fmt}/>
            </div>
            {showDiff && compareRun && (
              <RunDiff runA={compareRun} runB={selectedRun} onClose={()=>setShowDiff(false)}/>
            )}
          </>
        )}
      </div>
    </div>
  );
}

// ── RunDetail — check-by-check results for one run ───────────────────────────
function RunDetail({ run, T, dur, fmt }) {
  const [expanded,     setExpanded]     = React.useState({});
  const [explainTexts, setExplainTexts] = React.useState({});
  const [explainLoad,  setExplainLoad]  = React.useState({});

  const explainCheck = async (chk) => {
    if (chk.passed || explainTexts[chk.id||chk.name]) return;
    setExplainLoad(p=>({...p,[chk.id||chk.name]:true}));
    try {
      const r = await fetch(`${API}/api/ai/chat`,{method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          system:"Explain this data quality check failure in 1-2 plain English sentences for a business user. No SQL jargon. Focus on what it means and whether it needs urgent attention.",
          messages:[{role:"user",content:`Check "${chk.name}" failed with ${chk.row_count} rows. Condition: ${chk.pass_condition}. Severity: ${chk.severity}.`}],
          max_tokens:80
        })});
      const d = await r.json();
      setExplainTexts(p=>({...p,[chk.id||chk.name]:d?.content?.[0]?.text?.trim()||""}));
    } catch(e){}
    setExplainLoad(p=>({...p,[chk.id||chk.name]:false}));
  };
  const toggle = (id) => setExpanded(p=>({...p,[id]:!p[id]}));

  const passCount = (run.check_results||[]).filter(c=>c.passed).length;
  const failCount = (run.check_results||[]).filter(c=>!c.passed).length;
  const total     = (run.check_results||[]).length;

  return (
    <div>
      {/* Run summary */}
      <div style={{ display:"flex", gap:12, alignItems:"center", marginBottom:18, flexWrap:"wrap" }}>
        <div style={{ padding:"10px 16px", borderRadius:10,
          background:run.status==="clean"?`${T.green}10`:`${T.red}10`,
          border:`1px solid ${run.status==="clean"?T.green:T.red}25` }}>
          <div style={{ fontSize:20, fontWeight:800,
            color:run.status==="clean"?T.green:T.red }}>
            {run.status==="clean"?"✓ Clean":`${failCount} Failed`}
          </div>
          <div style={{ fontSize:10, color:T.muted }}>{fmt(run.started_at)}</div>
        </div>
        {[
          { label:"Total checks", value:total },
          { label:"Passed",       value:passCount, color:T.green },
          { label:"Failed",       value:failCount, color:failCount>0?T.red:T.muted },
          { label:"Duration",     value:run.duration_ms?dur(run.duration_ms):"—" },
          { label:"Triggered by", value:run.triggered_by==="cron"?"Schedule":"Manual" },
        ].map(s=>(
          <div key={s.label} style={{ padding:"10px 14px", borderRadius:10,
            background:T.surface, border:`1px solid ${T.border}`, textAlign:"center", minWidth:80 }}>
            <div style={{ fontSize:16, fontWeight:800, color:s.color||T.text }}>{s.value}</div>
            <div style={{ fontSize:10, color:T.muted, marginTop:2 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Progress bar */}
      {total > 0 && (
        <div style={{ marginBottom:16 }}>
          <div style={{ display:"flex", justifyContent:"space-between", fontSize:10, color:T.muted, marginBottom:4 }}>
            <span>Check results</span>
            <span>{passCount}/{total} passed</span>
          </div>
          <div style={{ height:6, background:T.border, borderRadius:99, overflow:"hidden" }}>
            <div className="wz-bar-fill" style={{ height:"100%", width:`${total>0?passCount/total*100:0}%`,
              background:failCount===0?T.green:`linear-gradient(90deg,${T.green},${T.orange})`,
              borderRadius:99, transition:"width 0.8s cubic-bezier(0.4,0,0.2,1)" }}/>
          </div>
        </div>
      )}

      {/* Per-check results */}
      <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
        {(run.check_results||[]).map((chk,i)=>(
          <div key={chk.id||i} style={{ borderRadius:10, overflow:"hidden",
            border:`1px solid ${chk.passed?T.green+"30":T.red+"30"}`,
            background:chk.passed?`${T.green}04`:`${T.red}04` }}>

            {/* Check header */}
            <div style={{ display:"flex", alignItems:"center", gap:10,
              padding:"10px 14px", cursor:"pointer" }}
              onClick={()=>toggle(chk.id||i)}>
              <div style={{ width:22, height:22, borderRadius:6, flexShrink:0,
                background:chk.passed?`${T.green}15`:`${T.red}15`,
                display:"flex", alignItems:"center", justifyContent:"center" }}>
                {chk.passed
                  ? <Check size={12} color={T.green}/>
                  : <X size={12} color={T.red}/>}
              </div>
              <div style={{ flex:1 }}>
                <div style={{ fontSize:12, fontWeight:700, color:T.text }}>{chk.name}</div>
                <div style={{ fontSize:10, color:T.muted, marginTop:1 }}>
                  {chk.error
                    ? <span style={{ color:T.red }}>{chk.error}</span>
                    : <>
                        {chk.row_count} rows · condition: <code style={{ fontFamily:"monospace", color:T.accent }}>{chk.pass_condition}</code>
                        {chk.duration_ms && ` · ${dur(chk.duration_ms)}`}
                      </>
                  }
                </div>
              </div>
              <Badge label={chk.severity||"high"} color={SEV_COLOR[chk.severity]||T.muted}/>
              {!chk.passed && (
                <button onClick={e=>{e.stopPropagation();explainCheck(chk);}}
                  style={{background:"none",border:`1px solid ${T.purple}30`,borderRadius:5,
                    padding:"2px 8px",cursor:"pointer",fontSize:9,color:T.purple,fontWeight:600,
                    opacity:explainTexts[chk.id||chk.name]?0.5:1}}>
                  {explainLoad[chk.id||chk.name]?<Spinner size={7}/>:"✨"} Explain
                </button>
              )}
              <span style={{ fontSize:12, color:T.dim }}>{expanded[chk.id||i]?"▴":"▾"}</span>
            </div>

            {/* Expanded: SQL + sample rows */}
            {expanded[chk.id||i] && (
              <div style={{ borderTop:`1px solid ${T.border}20`, padding:"10px 14px" }}>
                {explainTexts[chk.id||chk.name] && (
                  <div style={{ marginBottom:10, padding:"8px 10px", borderRadius:7,
                    background:`linear-gradient(135deg,${T.purple}08,${T.accent}05)`,
                    border:`1px solid ${T.purple}20`, fontSize:11, color:T.text, lineHeight:1.5,
                    display:"flex", gap:8 }}>
                    <span style={{flexShrink:0}}>✨</span>
                    <span>{explainTexts[chk.id||chk.name]}</span>
                  </div>
                )}
              {chk.sql && (
                  <div style={{ marginBottom:10 }}>
                    <div style={{ fontSize:10, fontWeight:600, color:T.muted, marginBottom:4 }}>SQL</div>
                    <pre style={{ margin:0, padding:"8px 10px", background:T.surface,
                      borderRadius:6, fontSize:11, fontFamily:"monospace",
                      border:`1px solid ${T.border}`, whiteSpace:"pre-wrap",
                      overflowX:"auto" }}>{chk.sql}</pre>
                  </div>
                )}
                {chk.sample_rows?.length > 0 && chk.columns?.length > 0 && (
                  <div>
                    <div style={{ fontSize:10, fontWeight:600, color:T.muted, marginBottom:4 }}>
                      Sample rows ({chk.sample_rows.length})
                    </div>
                    <div style={{ overflowX:"auto", borderRadius:6,
                      border:`1px solid ${T.border}` }}>
                      <table style={{ borderCollapse:"collapse", fontSize:10,
                        fontFamily:"monospace", width:"100%" }}>
                        <thead>
                          <tr style={{ background:`${T.accent}08` }}>
                            {chk.columns.map(c=>(
                              <th key={c} style={{ padding:"4px 10px", textAlign:"left",
                                fontWeight:700, fontSize:9, color:T.muted,
                                borderBottom:`1px solid ${T.border}`, whiteSpace:"nowrap",
                                textTransform:"uppercase" }}>{c}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {chk.sample_rows.map((row,ri)=>(
                            <tr key={ri}>
                              {chk.columns.map(c=>(
                                <td key={c} style={{ padding:"3px 10px",
                                  borderBottom:`1px solid ${T.border}20`,
                                  whiteSpace:"nowrap",
                                  color:row[c]===null?T.red:T.text2 }}>
                                  {row[c]===null?"NULL":String(row[c]).slice(0,50)}
                                </td>
                              ))}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

// ── AllRunsView — cross-workflow run history ───────────────────────────────────
function AllRunsView({ history, workflows, onBack, onOpenWf }) {
  const T = useT();
  const [filter, setFilter] = React.useState("all"); // all | failed | clean
  const [search, setSearch] = React.useState("");
  const debouncedSearch = useDebounce(search, 150);

  const wfMap = Object.fromEntries(workflows.map(w=>[w.id,w]));
  const filtered = history.filter(r=>{
    if (filter==="failed" && r.status!=="issues_found") return false;
    if (filter==="clean"  && r.status!=="clean")        return false;
    if (search && !r.workflow_name?.toLowerCase().includes(debouncedSearch.toLowerCase())) return false;
    return true;
  });

  return (
    <div style={{ overflowY:"auto", padding:"24px 28px", maxWidth:1000 }}>
      <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:20 }}>
        <Btn onClick={onBack} variant="ghost" size="sm">← Workflows</Btn>
        <div style={{ fontSize:18, fontWeight:700, color:T.text }}>All Runs</div>
        <div style={{ marginLeft:"auto", display:"flex", gap:8 }}>
          {["all","failed","clean"].map(f=>(
            <button key={f} onClick={()=>setFilter(f)}
              style={{ padding:"4px 12px", borderRadius:99, fontSize:11, cursor:"pointer",
                border:`1px solid ${filter===f?T.accent:T.border}`,
                background:filter===f?`${T.accent}10`:"transparent",
                color:filter===f?T.accent:T.muted, fontWeight:filter===f?700:400 }}>
              {f==="all"?"All":f==="failed"?"Failed":"Clean"}
            </button>
          ))}
          <input value={search} onChange={e=>setSearch(e.target.value)}
            placeholder="Filter by workflow…"
            style={{ padding:"4px 10px", borderRadius:7, fontSize:11,
              border:`1px solid ${T.border}`, background:T.surface,
              color:T.text, outline:"none", width:160 }}/>
        </div>
      </div>

      {/* Summary stats */}
      <div style={{ display:"flex", gap:10, marginBottom:16 }}>
        {[
          { label:"Total runs", value:history.length },
          { label:"Clean",  value:history.filter(r=>r.status==="clean").length, color:T.green },
          { label:"Failed", value:history.filter(r=>r.status!=="clean").length, color:history.some(r=>r.status!=="clean")?T.red:T.muted },
          { label:"Pass rate", value:history.length>0?Math.round(history.filter(r=>r.status==="clean").length/history.length*100)+"%":"—",
            color:T.accent },
        ].map(s=>(
          <div key={s.label} style={{ padding:"10px 14px", borderRadius:10,
            background:T.surface, border:`1px solid ${T.border}`, textAlign:"center", minWidth:80 }}>
            <div style={{ fontSize:18, fontWeight:800, color:s.color||T.text }}>{s.value}</div>
            <div style={{ fontSize:10, color:T.muted, marginTop:2 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Run rows */}
      <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
        {filtered.length===0 && (
          <div style={{ textAlign:"center", padding:"40px 0", color:T.dim, fontSize:12 }}>No runs match</div>
        )}
        {filtered.map(run=>{
          const wf = wfMap[run.workflow_id];
          const dur = run.duration_ms ? (run.duration_ms<1000?`${run.duration_ms}ms`:`${(run.duration_ms/1000).toFixed(1)}s`) : null;
          return (
            <div key={run.run_id}
              onClick={()=>wf&&onOpenWf(wf)}
              style={{ display:"flex", alignItems:"center", gap:12,
                padding:"10px 16px", borderRadius:10,
                background:T.card, border:`1px solid ${T.border}`,
                borderLeft:`3px solid ${run.status==="clean"?T.green:T.red}`,
                cursor:wf?"pointer":"default",
                boxShadow:"0 1px 3px rgba(0,0,0,0.04)" }}
              onMouseEnter={e=>{ if(wf) e.currentTarget.style.background=`${T.accent}04`; }}
              onMouseLeave={e=>{ e.currentTarget.style.background=T.card; }}>

              <div style={{ width:28, height:28, borderRadius:8, flexShrink:0,
                background:run.status==="clean"?`${T.green}15`:`${T.red}15`,
                display:"flex", alignItems:"center", justifyContent:"center" }}>
                {run.status==="clean"
                  ? <CheckCircle size={14} color={T.green}/>
                  : <XCircle size={14} color={T.red}/>}
              </div>

              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontSize:12, fontWeight:700, color:T.text,
                  overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                  {run.workflow_name}
                </div>
                <div style={{ fontSize:10, color:T.muted, marginTop:1 }}>
                  {run.started_at?.slice(0,16)?.replace("T"," ")}
                  {run.triggered_by==="cron" ? " · ⏰ scheduled" : " · ▶ manual"}
                </div>
              </div>

              {/* Check result pills */}
              <div style={{ display:"flex", gap:4, flexWrap:"wrap", maxWidth:240 }}>
                {(run.check_results||[]).slice(0,8).map((chk,i)=>(
                  <div key={chk.id||chk.name||i} title={chk.name}
                    style={{ width:10, height:10, borderRadius:2,
                      background:chk.passed?T.green:T.red, flexShrink:0 }}/>
                ))}
              </div>

              <div style={{ textAlign:"right", flexShrink:0 }}>
                <div style={{ fontSize:12, fontWeight:700,
                  color:run.status==="clean"?T.green:T.red }}>
                  {run.status==="clean"?"Clean":`${run.failed||0} fail`}
                </div>
                <div style={{ fontSize:10, color:T.dim }}>
                  {run.passed||0}/{run.total_checks||0} · {dur||"—"}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// AI WORKFLOW ASSISTANT — conversational workflow builder
// ═══════════════════════════════════════════════════════════════════════════════
function AiWorkflowAssistant({ workflows, dbSchema, onSave, onDelete, onRun, onClose, T }) {
  const [messages, setMessages] = React.useState([{
    role:"assistant",
    text:"I can build, edit, delete, run, or configure any workflow from plain text.\n\nTry: \"Create a workflow that checks for failed downloads in mws.report daily\" or \"Edit the daily brief to add a null check on orders\" or \"Run all workflows\" or \"Delete the X workflow\".",
    actions:[]
  }]);
  const [input,   setInput]   = React.useState("");
  const [loading, setLoading] = React.useState(false);
  const bottomRef = React.useRef(null);

  React.useEffect(()=>{
    if (bottomRef.current) bottomRef.current.scrollIntoView({behavior:"smooth"});
  }, [messages]);

  const send = async (textOverride) => {
    const text = (textOverride || input).trim();
    if (!text || loading) return;
    setInput("");
    setMessages(p=>[...p, {role:"user", text}, {role:"thinking"}]);
    setLoading(true);

    const history = messages.slice(-6).map(m=>({
      role: m.role==="user"?"user":"assistant",
      content: m.text||""
    })).filter(h=>h.content);

    const wfList = workflows.map(w=>
      `id:${w.id} name:"${w.name}" schedule:${w.schedule||"manual"} checks:${(w.checks||[]).length} enabled:${w.enabled!==false}`
    ).join("\n");

    const system = `You are WiziAgent, an AI that manages data quality workflows for a Redshift-based ecommerce analytics platform.

CURRENT WORKFLOWS:
${wfList || "None yet"}

FULL DATABASE SCHEMA (use ONLY these exact columns — never invent):
${dbSchema || "mws.report(status,download_date,report_type,copy_status), mws.orders(amazon_order_id,asin,status,purchase_date), mws.inventory(asin,available,snapshot_date), mws.sales_and_traffic_by_date(sale_date,ordered_revenue,sessions)"}

CAPABILITIES:
You can take these actions by returning structured JSON. Always return a JSON object with:
- "reply": your conversational response explaining what you did
- "actions": array of action objects

ACTION TYPES:
1. create_workflow: { type:"create_workflow", workflow:{ name, desc, schedule, checks:[{name,sql,pass_condition,severity}] } }
2. update_workflow: { type:"update_workflow", workflow_id:"id", changes:{ name?, desc?, schedule?, checks?, enabled? } }
3. delete_workflow: { type:"delete_workflow", workflow_id:"id", workflow_name:"name" }
4. run_workflow: { type:"run_workflow", workflow_id:"id", workflow_name:"name" }
5. add_check: { type:"add_check", workflow_id:"id", check:{ name, sql, pass_condition, severity } }
6. remove_check: { type:"remove_check", workflow_id:"id", check_name:"name" }
7. enable_workflow: { type:"enable_workflow", workflow_id:"id", enabled:true/false }

RULES FOR SQL:
- Use ONLY columns from the schema above. Never invent column names.
- Do NOT write SELECT COUNT(*) without a WHERE clause. Write meaningful checks.
- pass_condition: "rows = 0" (no bad rows), "rows > 0" (data present), "value > N"
- severity: critical|high|medium|low
- schedule options: "every 15 min", "every 30 min", "every 1 hour", "daily", "weekly", "manual"

Respond ONLY with a JSON object. No markdown, no backticks.
Example: {"reply":"Created a workflow with 2 checks for mws.report","actions":[{"type":"create_workflow","workflow":{...}}]}`;

    try {
      const res = await fetch(`${API}/api/ai/chat`, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          system,
          messages:[...history, {role:"user", content:text}],
          max_tokens:1200
        })
      });
      const data = await res.json();
      const raw  = data?.content?.[0]?.text || "{}";
      let parsed;
      try { parsed = JSON.parse(raw.replace(/```json|```/g,"").trim()); }
      catch(e) { parsed = { reply: raw, actions:[] }; }

      const reply   = parsed.reply   || "Done.";
      const actions = parsed.actions || [];
      const performed = [];

      for (const action of actions) {
        try {
          if (action.type === "create_workflow") {
            const wf = {
              ...action.workflow,
              id: `ai_wf_${Date.now().toString(36)}`,
              checks: (action.workflow.checks||[]).map((c,i)=>({...c, id:`c_${Date.now()}_${i}`})),
              created_at: new Date().toISOString(),
              enabled: true,
            };
            await onSave(wf);
            performed.push({ type:"created", name:wf.name, id:wf.id });
          }
          else if (action.type === "update_workflow") {
            const existing = workflows.find(w=>w.id===action.workflow_id
              || w.name.toLowerCase()===String(action.workflow_id||"").toLowerCase());
            if (existing) {
              const updated = { ...existing, ...action.changes,
                checks: action.changes.checks
                  ? action.changes.checks.map((c,i)=>({...c, id:c.id||`c_${Date.now()}_${i}`}))
                  : existing.checks
              };
              await onSave(updated);
              performed.push({ type:"updated", name:updated.name });
            }
          }
          else if (action.type === "delete_workflow") {
            const existing = workflows.find(w=>w.id===action.workflow_id
              || w.name.toLowerCase()===String(action.workflow_name||"").toLowerCase());
            if (existing) { await onDelete(existing.id); performed.push({ type:"deleted", name:existing.name }); }
          }
          else if (action.type === "run_workflow") {
            const existing = workflows.find(w=>w.id===action.workflow_id
              || w.name.toLowerCase()===String(action.workflow_name||"").toLowerCase());
            if (existing) { await onRun(existing); performed.push({ type:"ran", name:existing.name }); }
          }
          else if (action.type === "add_check") {
            const existing = workflows.find(w=>w.id===action.workflow_id);
            if (existing) {
              const updated = { ...existing, checks:[...existing.checks,
                {...action.check, id:`c_${Date.now()}`}] };
              await onSave(updated);
              performed.push({ type:"check_added", name:action.check.name, wf:existing.name });
            }
          }
          else if (action.type === "remove_check") {
            const existing = workflows.find(w=>w.id===action.workflow_id);
            if (existing) {
              const updated = { ...existing, checks:existing.checks.filter(
                c=>c.name.toLowerCase()!==String(action.check_name||"").toLowerCase()) };
              await onSave(updated);
              performed.push({ type:"check_removed", name:action.check_name, wf:existing.name });
            }
          }
          else if (action.type === "enable_workflow") {
            const existing = workflows.find(w=>w.id===action.workflow_id);
            if (existing) {
              const updated = { ...existing, enabled: action.enabled };
              await onSave(updated);
              performed.push({ type:action.enabled?"enabled":"disabled", name:existing.name });
            }
          }
        } catch(e) { performed.push({ type:"error", msg:e.message }); }
      }

      setMessages(p=>[
        ...p.filter(m=>m.role!=="thinking"),
        { role:"assistant", text:reply, actions:performed }
      ]);
    } catch(e) {
      setMessages(p=>[...p.filter(m=>m.role!=="thinking"),
        { role:"assistant", text:`Error: ${e.message}`, actions:[] }]);
    }
    setLoading(false);
  };

  const SUGGESTIONS = [
    "Create a workflow checking for failed downloads today",
    "Add a null check on mws.orders.asin to Daily Brief",
    "Schedule the daily brief to run every hour",
    "Show me all my workflows",
    "Delete the test workflow",
    "Run all enabled workflows",
    "Create 3 data quality checks for mws.inventory",
  ];

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%",
      background:T.surface, borderLeft:`1px solid ${T.border}` }}>

      {/* Header */}
      <div style={{ padding:"14px 18px", borderBottom:`1px solid ${T.border}`,
        display:"flex", alignItems:"center", gap:10, flexShrink:0,
        background:`linear-gradient(135deg,${T.accent}08,${T.purple}08)` }}>
        <div style={{ width:32, height:32, borderRadius:9,
          background:`linear-gradient(135deg,${T.accent},${T.purple})`,
          display:"flex", alignItems:"center", justifyContent:"center",
          fontSize:16, flexShrink:0 }}>🤖</div>
        <div style={{ flex:1 }}>
          <div style={{ fontSize:13, fontWeight:700, color:T.text }}>AI Workflow Assistant</div>
          <div style={{ fontSize:9, color:T.muted }}>Build · Edit · Delete · Run · Configure</div>
        </div>
        <button onClick={onClose}
          style={{ background:"none", border:"none", cursor:"pointer",
            color:T.muted, fontSize:18, lineHeight:1 }}>×</button>
      </div>

      {/* Messages */}
      <div style={{ flex:1, overflowY:"auto", padding:"14px 16px",
        display:"flex", flexDirection:"column", gap:10 }}>

        {/* Suggestions on empty */}
        {messages.length === 1 && (
          <div style={{ marginBottom:4 }}>
            <div style={{ fontSize:10, color:T.muted, fontWeight:600,
              textTransform:"uppercase", letterSpacing:"0.06em", marginBottom:8 }}>
              Try asking…
            </div>
            <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>
              {SUGGESTIONS.map(s=>(
                <button key={s} onClick={()=>send(s)}
                  style={{ fontSize:10, padding:"4px 10px", borderRadius:99,
                    border:`1px solid ${T.accent}30`, background:`${T.accent}06`,
                    color:T.accent, cursor:"pointer", fontFamily:"inherit" }}>
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((m,i)=>(
          <div key={m.ts||m.text?.slice(0,20)||i}>
            {m.role==="user" && (
              <div style={{ display:"flex", justifyContent:"flex-end" }}>
                <div style={{ maxWidth:"82%", padding:"9px 13px", borderRadius:12,
                  borderBottomRightRadius:3, fontSize:12, lineHeight:1.5,
                  background:`linear-gradient(135deg,${T.accent},${T.purple})`,
                  color:"white", whiteSpace:"pre-wrap" }}>
                  {m.text}
                </div>
              </div>
            )}
            {m.role==="thinking" && (
              <div style={{ display:"flex", alignItems:"center", gap:6,
                color:T.muted, fontSize:11 }}>
                <Spinner size={10}/> <span style={{fontStyle:"italic"}}>Working on it…</span>
              </div>
            )}
            {m.role==="assistant" && (
              <div>
                {/* Action chips */}
                {(m.actions||[]).length > 0 && (
                  <div style={{ display:"flex", flexWrap:"wrap", gap:5, marginBottom:6 }}>
                    {m.actions.map((a,ai)=>{
                      const chipColor = a.type==="error"?T.red:a.type==="deleted"?T.orange:T.green;
                      const chipLabel = a.type==="created"?`✨ Created: ${a.name}`
                        :a.type==="updated"?`✏ Updated: ${a.name}`
                        :a.type==="deleted"?`🗑 Deleted: ${a.name}`
                        :a.type==="ran"?`▶ Running: ${a.name}`
                        :a.type==="enabled"?`✓ Enabled: ${a.name}`
                        :a.type==="disabled"?`⏸ Paused: ${a.name}`
                        :a.type==="check_added"?`+ Check added to ${a.wf}`
                        :a.type==="check_removed"?`- Check removed from ${a.wf}`
                        :a.type==="error"?`✗ ${a.msg}`:a.type;
                      return (
                        <span key={ai} style={{ fontSize:10, padding:"3px 10px",
                          borderRadius:99, background:`${chipColor}10`,
                          border:`1px solid ${chipColor}30`, color:chipColor, fontWeight:600 }}>
                          {chipLabel}
                        </span>
                      );
                    })}
                  </div>
                )}
                {/* Reply text */}
                <div style={{ padding:"9px 12px", borderRadius:10, borderBottomLeftRadius:3,
                  fontSize:12, lineHeight:1.6, color:T.text,
                  background:T.card, border:`1px solid ${T.border}`,
                  whiteSpace:"pre-wrap", maxWidth:"90%" }}>
                  {m.text}
                </div>
              </div>
            )}
          </div>
        ))}
        <div ref={bottomRef}/>
      </div>

      {/* Input */}
      <div style={{ padding:"10px 14px", borderTop:`1px solid ${T.border}`,
        flexShrink:0, background:T.surface }}>
        <div style={{ display:"flex", gap:8, alignItems:"flex-end" }}>
          <textarea
            value={input}
            onChange={e=>setInput(e.target.value)}
            onKeyDown={e=>{ if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();} }}
            placeholder="Describe what you want to build, change, or do…"
            rows={1}
            style={{ flex:1, padding:"8px 11px", borderRadius:9, fontSize:12,
              border:`1px solid ${T.border}`, background:T.bg, color:T.text,
              outline:"none", fontFamily:"inherit", resize:"none",
              lineHeight:1.4, maxHeight:100, overflowY:"auto" }}
            onInput={e=>{ e.target.style.height="auto"; e.target.style.height=Math.min(e.target.scrollHeight,100)+"px"; }}
            onFocus={e=>e.target.style.borderColor=T.accent}
            onBlur={e=>e.target.style.borderColor=T.border}
          />
          <button onClick={()=>send()} disabled={!input.trim()||loading}
            style={{ width:34, height:34, borderRadius:8, flexShrink:0, border:"none",
              background:(!input.trim()||loading)?T.border:`linear-gradient(135deg,${T.accent},${T.purple})`,
              cursor:(!input.trim()||loading)?"not-allowed":"pointer",
              display:"flex", alignItems:"center", justifyContent:"center", color:"white" }}>
            {loading?<Spinner size={12} color="white"/>:<ArrowRight size={14}/>}
          </button>
        </div>
        <div style={{ fontSize:9, color:T.dim, marginTop:4, textAlign:"center" }}>
          Enter to send · Shift+Enter for newline
        </div>
      </div>
    </div>
  );
}


// ── WorkflowBuilder — create / edit workflow with SQL checks ─────────────────
function WorkflowBuilder({ initial, dbSchema: dbSchemaProp, onSave, onCancel }) {
  const T = useT();
  const schemaFromHook = useSchema();
  const dbSchema = dbSchemaProp || schemaFromHook;
  const blank = {
    name:"", desc:"", schedule:"every 30 min", enabled:true,
    checks:[], tables:[], db_key:"default", slack_channel:"", schema_group:""
  };
  const [wf,        setWf]        = React.useState(initial ? {...blank,...initial, checks:[...(initial.checks||[])]} : blank);
  const [checkDraft,setDraft]     = React.useState({ name:"", sql:"", pass_condition:"rows = 0", severity:"high", source_id:"default" });
  const [editing,   setEditingCk] = React.useState(null); // check id being edited
  const [aiLoading, setAiLoad]    = React.useState(false);
  const [aiDesc,    setAiDesc]    = React.useState("");
  const [testResult,setTestResult]= React.useState(null);
  const [testing,   setTesting]   = React.useState(false);
  const [sources,   setSources]   = React.useState([{id:"default",name:"Default (Redshift)",type:"redshift"}]);
  const [dryRunning, setDryRunning] = React.useState(false);
  const [dryResults, setDryResults] = React.useState(null); // {passed, failed, results:[]}

  // Load configured data sources
  React.useEffect(()=>{
    fetch(`${API}/api/datasources`).then(r=>r.json()).then(d=>{
      if (d.sources) setSources(d.sources);
    }).catch(()=>{});
  }, []);

  const field   = (k,v) => setWf(p=>({...p,[k]:v}));
  const addCheck = () => {
    if (!checkDraft.name.trim() || !checkDraft.sql.trim()) return;
    const newChk = {...checkDraft, id:Date.now().toString(36)};
    setWf(p=>({...p, checks:[...p.checks, newChk]}));
    setDraft({ name:"", sql:"", pass_condition:"rows = 0", severity:"high", source_id:"default" });
    setTestResult(null);
  };
  const removeCheck = (id) => setWf(p=>({...p, checks:p.checks.filter(c=>c.id!==id)}));
  const moveCheck   = (id, dir) => setWf(p=>{
    const arr = [...p.checks];
    const i   = arr.findIndex(c=>c.id===id);
    const j   = i+dir;
    if (j<0||j>=arr.length) return p;
    [arr[i],arr[j]] = [arr[j],arr[i]];
    return {...p, checks:arr};
  });

  // AI check generator
  const aiGenCheck = async () => {
    if (!aiDesc.trim()) return;
    setAiLoad(true);
    try {
      const res  = await fetch(`${API}/api/ai/chat`, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          system:`You are a senior data engineering lead at an ecommerce analytics company. You write creative, high-signal SQL data quality checks that go far beyond basic null checks and row counts.

FULL DATABASE SCHEMA (use ONLY these exact columns — never invent):
${dbSchema || "mws.report(status,download_date,report_type,copy_status,tries,requested_date), mws.orders(amazon_order_id,asin,status,purchase_date,item_price,quantity,fulfillment_channel), mws.inventory(asin,available,reserved,inbound,snapshot_date), mws.sales_and_traffic_by_date(sale_date,ordered_revenue,ordered_units,sessions,page_views), mws.sales_and_traffic_by_asin(asin,sale_date,ordered_revenue,buy_box_prcntg), public.tbl_amzn_campaign_report(profile_id,report_date,impressions,clicks,spend,sales), public.tbl_amzn_keyword_report(profile_id,report_date,keyword_text,impressions,clicks,spend), public.tbl_amzn_product_ad_report(profile_id,report_date,asin,impressions,clicks,spend,sales), public.tbl_amzn_targets_report(profile_id,report_date,impressions,clicks,spend)"}

Think like a detective. Great checks catch things like:
- Cross-table anomalies: orders with no matching inventory, campaigns with spend but no sales
- Statistical outliers: revenue 3x higher or lower than 7-day average
- Pipeline timing issues: data arriving later than expected, gaps in date sequences
- Business logic violations: negative prices, impossible quantities, refund > original order
- Data drift: sudden change in distribution of a categorical column
- Completeness gaps: accounts/ASINs present yesterday but missing today
- Referential integrity: foreign key mismatches between tables
- Freshness windows: specific tables that must update within N hours of a trigger event

Rules:
- Use ONLY columns from the schema above
- SQL must be SELECT only
- Avoid bare SELECT COUNT(*) — return the actual suspect rows or aggregated signal
- pass_condition: "rows = 0" (no violations), "rows > 0" (data must exist), "value > N", "value = N"
- severity: critical|high|medium|low

${aiDesc.toLowerCase().includes("suggest") || aiDesc.toLowerCase().includes("ideas") || aiDesc.toLowerCase().includes("multiple") || aiDesc.toLowerCase().includes("give me") ?
`Return a JSON ARRAY of 3-5 diverse, creative checks:\n[{"name":"...","sql":"...","pass_condition":"...","severity":"...","explanation":"..."}]` :
`Return a single JSON object:\n{"name":"...","sql":"...","pass_condition":"...","severity":"...","explanation":"..."}`}

No markdown, no backticks.`,
          messages:[{role:"user", content:aiDesc}],
          max_tokens:1200
        })
      });
      const data = await res.json();
      const text = data?.content?.[0]?.text || "{}";
      const cleaned = text.replace(/```json|```/g,"").trim();
      const parsed = JSON.parse(cleaned);
      // Handle both single object and array of checks
      const checks = Array.isArray(parsed) ? parsed : (parsed.sql ? [parsed] : []);
      if (checks.length > 0) {
        if (checks.length === 1) {
          // Single check → load into draft editor
          setDraft({
            name: checks[0].name || aiDesc.slice(0,40),
            sql:  checks[0].sql,
            pass_condition: checks[0].pass_condition || "rows = 0",
            severity: checks[0].severity || "high",
          });
        } else {
          // Multiple checks → add all directly to the workflow
          setWf(p=>({...p, checks:[...p.checks,
            ...checks.map((c,i)=>({
              id: `ai_${Date.now()}_${i}`,
              name: c.name||`AI Check ${i+1}`,
              sql: c.sql||"",
              pass_condition: c.pass_condition||"rows = 0",
              severity: c.severity||"high",
            }))
          ]}));
        }
        setAiDesc("");
      }
    } catch(e) {}
    setAiLoad(false);
  };

  // Test SQL
  const testSql = async () => {
    if (!checkDraft.sql.trim()) return;
    setTesting(true); setTestResult(null);
    try {
      const res  = await fetch(`${API}/api/query?sql=${encodeURIComponent(checkDraft.sql + " LIMIT 5")}`);
      const data = await res.json();
      setTestResult(data);
    } catch(e) { setTestResult({error:e.message}); }
    setTesting(false);
  };

  const inp = { width:"100%", padding:"7px 10px", borderRadius:7, fontSize:12,
    border:`1px solid ${T.border}`, background:T.surface, color:T.text,
    fontFamily:"inherit", outline:"none", boxSizing:"border-box" };

  const runDryRun = async () => {
    if (!wf.checks.length) return;
    setDryRunning(true); setDryResults(null);
    const results = [];
    for (const chk of wf.checks) {
      if (!chk.sql?.trim()) continue;
      try {
        const r = await fetch(`${API}/api/query?sql=${encodeURIComponent(chk.sql + " LIMIT 5")}`);
        const d = await r.json();
        results.push({ name:chk.name, ok:!d.error, error:d.error||null,
          rows: d.rows?.length??0, pass_condition:chk.pass_condition });
      } catch(e) {
        results.push({ name:chk.name, ok:false, error:e.message, rows:0 });
      }
    }
    const passed = results.filter(r=>r.ok).length;
    setDryResults({ passed, failed:results.length-passed, results });
    setDryRunning(false);
  };

  return (
    <div style={{ overflowY:"auto", padding:"24px 28px", maxWidth:800 }}>
      <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:22 }}>
        <Btn onClick={onCancel} variant="ghost" size="sm">← Back</Btn>
        <div style={{ fontSize:18, fontWeight:700, color:T.text }}>
          {initial ? "Edit Workflow" : "New Workflow"}
        </div>
        <div style={{ marginLeft:"auto", display:"flex", gap:8 }}>
          <Btn onClick={runDryRun} disabled={dryRunning||!wf.checks.length} variant="ghost" size="sm">
            {dryRunning?<Spinner size={9}/>:<Play size={9}/>} Dry Run
          </Btn>
          <Btn onClick={()=>onSave(wf)} disabled={!wf.name.trim()}
            style={{ background:`linear-gradient(135deg,${T.accent},${T.purple})`,
              color:"white", border:"none" }}>
            <Check size={11}/> Save Workflow
          </Btn>
        </div>
      </div>

      {dryResults && (
        <div style={{ marginBottom:14, padding:"12px 16px", borderRadius:8,
          border:`1px solid ${dryResults.failed>0?T.red:T.green}30`,
          background:`${dryResults.failed>0?T.red:T.green}06` }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
            <span style={{ fontSize:12, fontWeight:700,
              color:dryResults.failed>0?T.red:T.green }}>
              {dryResults.failed>0
                ? `⚠ Dry run: ${dryResults.failed} check(s) have SQL errors`
                : `✓ Dry run passed — all ${dryResults.passed} check(s) execute without errors`}
            </span>
            <button onClick={()=>setDryResults(null)}
              style={{ background:"none", border:"none", cursor:"pointer",
                color:T.muted, fontSize:14 }}>×</button>
          </div>
          {dryResults.results.map((r,i)=>(
            <div key={r.name||i} style={{ fontSize:11, color:r.ok?T.green:T.red,
              display:"flex", gap:8, marginTop:4 }}>
              <span>{r.ok?"✓":"✗"}</span>
              <span style={{ fontWeight:600 }}>{r.name}</span>
              {r.error && <span style={{ color:T.red, fontFamily:"monospace" }}>— {r.error.slice(0,80)}</span>}
              {r.ok && <span style={{ color:T.muted }}>({r.rows} rows)</span>}
            </div>
          ))}
        </div>
      )}

      <div style={{ display:"flex", flexDirection:"column", gap:14 }}>

        {/* Basic info */}
        <Card style={{ padding:"18px 20px" }}>
          <div style={{ fontSize:12, fontWeight:700, color:T.muted, marginBottom:12,
            textTransform:"uppercase", letterSpacing:"0.05em" }}>Workflow Info</div>
          <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
            <div>
              <label style={{ fontSize:11, fontWeight:600, color:T.text2, display:"block", marginBottom:3 }}>Name *</label>
              <input value={wf.name} onChange={e=>field("name",e.target.value)}
                placeholder="e.g. Amazon Data Quality Check"
                style={inp} onFocus={e=>e.target.style.borderColor=T.accent}
                onBlur={e=>e.target.style.borderColor=T.border}/>
            </div>
            <div>
              <label style={{ fontSize:11, fontWeight:600, color:T.text2, display:"block", marginBottom:3 }}>Description</label>
              <input value={wf.desc} onChange={e=>field("desc",e.target.value)}
                placeholder="What does this workflow check?"
                style={inp} onFocus={e=>e.target.style.borderColor=T.accent}
                onBlur={e=>e.target.style.borderColor=T.border}/>
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
              <div>
                <label style={{ fontSize:11, fontWeight:600, color:T.text2, display:"block", marginBottom:3 }}>Schedule</label>
                <select value={wf.schedule} onChange={e=>field("schedule",e.target.value)} style={inp}>
                  {SCHEDULE_OPTS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}
                </select>
              </div>
              <div>
                <label style={{ fontSize:11, fontWeight:600, color:T.text2, display:"block", marginBottom:3 }}>Slack Webhook (optional)</label>
                <input value={wf.slack_channel} onChange={e=>field("slack_channel",e.target.value)}
                  placeholder="https://hooks.slack.com/…"
                  style={inp} onFocus={e=>e.target.style.borderColor=T.accent}
                  onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:8 }}>
              <input type="checkbox" id="wf-enabled" checked={wf.enabled!==false}
                onChange={e=>field("enabled",e.target.checked)}/>
              <label htmlFor="wf-enabled" style={{ fontSize:12, color:T.text2, cursor:"pointer" }}>
                Enabled (run on schedule)
              </label>
            </div>
          </div>
        </Card>

        {/* SQL Checks */}
        <Card style={{ padding:"18px 20px" }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12 }}>
            <div style={{ fontSize:12, fontWeight:700, color:T.muted,
              textTransform:"uppercase", letterSpacing:"0.05em" }}>
              SQL Checks ({wf.checks.length})
            </div>
          </div>

          {/* Existing checks — inline editable */}
          {wf.checks.length > 0 && (
            <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:14 }}>
              {wf.checks.map((chk,i)=>{
                const isEditing = editing === chk.id;
                const updateField = (k,v) => setWf(p=>({...p, checks:p.checks.map(c=>c.id===chk.id?{...c,[k]:v}:c)}));
                return (
                  <div key={chk.id} style={{ borderRadius:8, overflow:"hidden",
                    border:`1px solid ${isEditing ? T.accent : SEV_COLOR[chk.severity]||T.muted}40`,
                    background: isEditing ? `${T.accent}04` : `${SEV_COLOR[chk.severity]||T.muted}04` }}>
                    {/* Collapsed row */}
                    {!isEditing && (
                      <div style={{ display:"flex", alignItems:"center", gap:8, padding:"9px 12px" }}>
                        <div style={{ width:6, height:6, borderRadius:"50%", flexShrink:0,
                          background: SEV_COLOR[chk.severity]||T.muted }}/>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontSize:12, fontWeight:700, color:T.text }}>{chk.name}</div>
                          <div style={{ fontSize:10, color:T.muted, fontFamily:"monospace",
                            overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                            {chk.sql}
                          </div>
                          <div style={{ fontSize:10, color:T.dim, marginTop:1 }}>
                            Pass when: <code style={{ fontFamily:"monospace", color:T.accent }}>{chk.pass_condition}</code>
                            {" · "}<Badge label={chk.severity} color={SEV_COLOR[chk.severity]||T.muted}/>
                            {chk.source_id && chk.source_id !== "default" && (
                              <span style={{ marginLeft:5, fontSize:9, padding:"1px 6px", borderRadius:4,
                                background:`${T.purple}15`, color:T.purple, fontWeight:600 }}>
                                🔗 {(sources.find(s=>s.id===chk.source_id)||{}).name || chk.source_id}
                              </span>
                            )}
                          </div>
                        </div>
                        <div style={{ display:"flex", gap:4, flexShrink:0 }}>
                          <button onClick={()=>setEditingCk(chk.id)} title="Edit"
                            style={{ background:"none", border:`1px solid ${T.border}`, borderRadius:5,
                              cursor:"pointer", color:T.muted, fontSize:11, padding:"2px 8px",
                              transition:"all 0.1s" }}
                            onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}
                            onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.muted;}}>
                            ✏️ Edit
                          </button>
                          <button onClick={()=>moveCheck(chk.id,-1)} disabled={i===0}
                            style={{ background:"none", border:"none", cursor:i===0?"not-allowed":"pointer",
                              color:T.dim, fontSize:12, opacity:i===0?0.3:1 }}>↑</button>
                          <button onClick={()=>moveCheck(chk.id,1)} disabled={i===wf.checks.length-1}
                            style={{ background:"none", border:"none", cursor:i===wf.checks.length-1?"not-allowed":"pointer",
                              color:T.dim, fontSize:12, opacity:i===wf.checks.length-1?0.3:1 }}>↓</button>
                          <button onClick={()=>removeCheck(chk.id)}
                            style={{ background:"none", border:"none", cursor:"pointer", color:T.red, fontSize:14 }}>×</button>
                        </div>
                      </div>
                    )}
                    {/* Expanded inline editor */}
                    {isEditing && (
                      <div style={{ padding:"12px 14px", display:"flex", flexDirection:"column", gap:8 }}>
                        <div style={{ fontSize:11, fontWeight:700, color:T.accent, marginBottom:2 }}>
                          ✏️ Editing: {chk.name || "check"}
                        </div>
                        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
                          <div>
                            <label style={{ fontSize:10, fontWeight:600, color:T.muted, display:"block", marginBottom:2 }}>Name</label>
                            <input value={chk.name} onChange={e=>updateField("name",e.target.value)}
                              style={{ width:"100%", padding:"6px 10px", borderRadius:6, fontSize:11,
                                border:`1px solid ${T.border}`, background:T.surface, color:T.text,
                                fontFamily:"inherit", outline:"none", boxSizing:"border-box" }}
                              onFocus={e=>e.target.style.borderColor=T.accent}
                              onBlur={e=>e.target.style.borderColor=T.border}/>
                          </div>
                          <div>
                            <label style={{ fontSize:10, fontWeight:600, color:T.muted, display:"block", marginBottom:2 }}>Severity</label>
                            <select value={chk.severity} onChange={e=>updateField("severity",e.target.value)}
                              style={{ width:"100%", padding:"6px 10px", borderRadius:6, fontSize:11,
                                border:`1px solid ${T.border}`, background:T.surface, color:T.text,
                                fontFamily:"inherit", outline:"none" }}>
                              {["critical","high","medium","low"].map(s=><option key={s} value={s}>{s}</option>)}
                            </select>
                          </div>
                        </div>
                        <div>
                          <label style={{ fontSize:10, fontWeight:600, color:T.muted, display:"block", marginBottom:2 }}>SQL Query</label>
                          <textarea value={chk.sql} rows={3} onChange={e=>updateField("sql",e.target.value)}
                            style={{ width:"100%", padding:"6px 10px", borderRadius:6, fontSize:11,
                              border:`1px solid ${T.border}`, background:T.surface, color:T.text,
                              fontFamily:"monospace", outline:"none", boxSizing:"border-box", resize:"vertical" }}
                            onFocus={e=>e.target.style.borderColor=T.accent}
                            onBlur={e=>e.target.style.borderColor=T.border}/>
                        </div>
                        <div>
                          <label style={{ fontSize:10, fontWeight:600, color:T.muted, display:"block", marginBottom:2 }}>Pass when</label>
                          <PassConditionPicker
                            value={chk.pass_condition || "rows = 0"}
                            onChange={v => updateField("pass_condition", v)}
                          />
                        </div>
                        <div>
                          <label style={{ fontSize:10, fontWeight:600, color:T.muted, display:"block", marginBottom:2 }}>Data Source</label>
                          <select value={chk.source_id || "default"} onChange={e=>updateField("source_id",e.target.value)}
                            style={{ width:"100%", padding:"6px 10px", borderRadius:6, fontSize:11,
                              border:`1px solid ${T.border}`, background:T.surface, color:T.text,
                              fontFamily:"inherit", outline:"none" }}>
                            {sources.map(s=>(
                              <option key={s.id} value={s.id}>{s.name} ({s.type})</option>
                            ))}
                          </select>
                        </div>
                        <div style={{ display:"flex", gap:6 }}>
                          <Btn size="sm" onClick={()=>setEditingCk(null)}
                            style={{ background:T.green, color:"white", border:"none" }}>
                            <Check size={10}/> Done
                          </Btn>
                          <Btn size="sm" variant="muted" onClick={()=>removeCheck(chk.id)}>
                            <Trash2 size={10}/> Remove
                          </Btn>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}

          {/* AI check generator */}
          <div style={{ padding:"12px 14px", borderRadius:8, marginBottom:12,
            background:`${T.purple}05`, border:`1px solid ${T.purple}20` }}>
            <div style={{ fontSize:11, fontWeight:600, color:T.purple, marginBottom:8,
              display:"flex", alignItems:"center", gap:5 }}>
              <Zap size={11}/> AI Check Generator
            </div>
            <div style={{ display:"flex", gap:8 }}>
              <input value={aiDesc} onChange={e=>setAiDesc(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&aiGenCheck()}
                placeholder="Describe what to check, e.g. 'Find orders with null ASIN in the last 7 days'"
                style={{...inp, flex:1}} onFocus={e=>e.target.style.borderColor=T.purple}
                onBlur={e=>e.target.style.borderColor=T.border}/>
              <Btn onClick={aiGenCheck} disabled={aiLoading||!aiDesc.trim()} size="sm"
                variant="ghost" style={{ color:T.purple, borderColor:`${T.purple}40` }}>
                {aiLoading?<Spinner size={10}/>:<Zap size={10}/>} Generate
              </Btn>
            </div>
          </div>

          {/* Manual check form */}
          <div style={{ display:"flex", flexDirection:"column", gap:8,
            padding:"12px 14px", borderRadius:8, background:T.surface,
            border:`1px solid ${T.border}` }}>
            <div style={{ fontSize:11, fontWeight:600, color:T.muted, marginBottom:2 }}>Add Check</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
              <div>
                <label style={{ fontSize:10, fontWeight:600, color:T.text2, display:"block", marginBottom:2 }}>Check Name</label>
                <input value={checkDraft.name} onChange={e=>setDraft(p=>({...p,name:e.target.value}))}
                  placeholder="e.g. Null ASINs in orders"
                  style={inp} onFocus={e=>e.target.style.borderColor=T.accent}
                  onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:6 }}>
                <div>
                  <label style={{ fontSize:10, fontWeight:600, color:T.text2, display:"block", marginBottom:2 }}>Pass When</label>
                  <PassConditionPicker
                    value={checkDraft.pass_condition || "rows = 0"}
                    onChange={v => setDraft(p=>({...p, pass_condition:v}))}
                  />
                </div>
                <div>
                  <label style={{ fontSize:10, fontWeight:600, color:T.text2, display:"block", marginBottom:2 }}>Severity</label>
                  <select value={checkDraft.severity}
                    onChange={e=>setDraft(p=>({...p,severity:e.target.value}))} style={inp}>
                    {["critical","high","medium","low"].map(s=><option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
              <div>
                <label style={{ fontSize:10, fontWeight:600, color:T.text2, display:"block", marginBottom:2 }}>Data Source</label>
                <select value={checkDraft.source_id || "default"}
                  onChange={e=>setDraft(p=>({...p,source_id:e.target.value}))} style={inp}>
                  {sources.map(s=>(
                    <option key={s.id} value={s.id}>
                      {s.name} ({s.type})
                    </option>
                  ))}
                </select>
              </div>
              </div>
            </div>
            <div>
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:2 }}>
                <label style={{ fontSize:10, fontWeight:600, color:T.text2 }}>SQL Query</label>
                <div style={{ display:"flex", gap:8 }}>
                  {(() => {
                    const [validating, setValidating] = React.useState(false);
                    const [valResult,  setValResult]  = React.useState(null);
                    const validate = async () => {
                      if (!checkDraft.sql.trim()) return;
                      setValidating(true); setValResult(null);
                      try {
                        const r = await fetch(`${API}/api/ai/validate-sql`, {
                          method:"POST", headers:{"Content-Type":"application/json"},
                          body:JSON.stringify({sql: checkDraft.sql})
                        });
                        setValResult(await r.json());
                      } catch(e) {}
                      setValidating(false);
                    };
                    return (
                      <>
                        {valResult && (
                          <span style={{ fontSize:9, fontWeight:700,
                            color:valResult.valid?T.green:T.red }}>
                            {valResult.valid?"✓ Valid":"✗ Issues"}
                          </span>
                        )}
                        <button onClick={validate} disabled={validating||!checkDraft.sql.trim()}
                          style={{ fontSize:10, color:T.purple, background:"none", border:"none",
                            cursor:"pointer", fontWeight:600 }}>
                          {validating?<Spinner size={9}/>:"✓"} Validate
                        </button>
                      </>
                    );
                  })()}
                  <button onClick={testSql} disabled={testing||!checkDraft.sql.trim()}
                    style={{ fontSize:10, color:T.accent, background:"none", border:"none",
                      cursor:"pointer", fontWeight:600 }}>
                    {testing?<Spinner size={9}/>:null} ↻ Test SQL
                  </button>
                </div>
              </div>
              <textarea value={checkDraft.sql} rows={3}
                onChange={e=>setDraft(p=>({...p,sql:e.target.value}))}
                placeholder={"SELECT asin, status, purchase_date, item_price\nFROM mws.orders\nWHERE status = \'Shipped\' AND item_price <= 0\nORDER BY purchase_date DESC\nLIMIT 100"}
                style={{...inp, fontFamily:"monospace", fontSize:11, resize:"vertical"}}
                onFocus={e=>e.target.style.borderColor=T.accent}
                onBlur={e=>e.target.style.borderColor=T.border}/>
              {/* Column hint chips — derived from dbSchema, zero tokens */}
              {checkDraft.sql && (() => {
                // Find which table is mentioned in the SQL and show its columns
                const schemaLines = (dbSchema||"").split(";");
                const mentioned = schemaLines.find(s => checkDraft.sql.toLowerCase().includes(s.split("(")[0].trim().toLowerCase()));
                if (!mentioned) return null;
                const cols = mentioned.match(/\(([^)]+)\)/)?.[1]?.split(",").map(c=>c.trim()) || [];
                if (!cols.length) return null;
                return (
                  <div style={{ marginTop:4, display:"flex", flexWrap:"wrap", gap:4 }}>
                    <span style={{ fontSize:9, color:T.dim, alignSelf:"center" }}>cols:</span>
                    {cols.slice(0,12).map(col=>(
                      <button key={col}
                        onClick={()=>setDraft(p=>({...p,sql:p.sql+col}))}
                        style={{ fontSize:9, padding:"1px 6px", borderRadius:4,
                          border:`1px solid ${T.border}`, background:T.surface,
                          color:T.muted, cursor:"pointer", fontFamily:"monospace" }}>
                        {col}
                      </button>
                    ))}
                  </div>
                );
              })()}
            </div>

            {/* Test result */}
            {testResult && (
              <div style={{ padding:"8px 10px", borderRadius:6, fontSize:11,
                background:testResult.error?`${T.red}08`:`${T.green}08`,
                border:`1px solid ${testResult.error?T.red:T.green}25`,
                fontFamily:"monospace" }}>
                {testResult.error
                  ? <span style={{ color:T.red }}>✗ {testResult.error}</span>
                  : <span style={{ color:T.green }}>✓ {testResult.rows?.length} rows · columns: {testResult.columns?.join(", ")}</span>
                }
              </div>
            )}

            <Btn onClick={addCheck}
              disabled={!checkDraft.name.trim()||!checkDraft.sql.trim()} size="sm"
              style={{ alignSelf:"flex-start" }}>
              <Plus size={10}/> Add Check
            </Btn>
          </div>
        </Card>
      </div>
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════════════════════
// RESULTS TAB — Full workflow run data viewer
// ═══════════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════════
// WIZI ASSISTANT — AI-driven 3-surface system
// 1. PostRunPanel  — pops up after workflow run with failures
// 2. AiBriefPanel  — AI section in Daily Brief tab
// 3. FloatingAssistant — persistent chat panel
// ═══════════════════════════════════════════════════════════════════════════════

// Shared hook — triggers AI analysis after a run
function useRunAnalysis(run, enabled=true) {
  const [analysis, setAnalysis] = React.useState(null);
  const [loading,  setLoading]  = React.useState(false);
  const [error,    setError]    = React.useState(null);

  const analyse = React.useCallback(async (r) => {
    if (!r || r.status==="clean" || !enabled) return;
    setLoading(true); setError(null);
    try {
      const res = await fetch(`${API}/api/ai/analyse-run`, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({ run: r })
      });
      const d = await res.json();
      if (d.error) setError(d.error);
      else setAnalysis(d);
    } catch(e) { setError(e.message); }
    setLoading(false);
  }, [enabled]);

  React.useEffect(() => {
    if (run && run.status!=="clean") analyse(run);
  }, [run?.run_id]);

  return { analysis, loading, error, analyse };
}


// ── 1. POST-RUN PANEL — modal that appears after a failed run ─────────────────
function PostRunPanel({ run, onClose, onSendToTriage, onNavigateResults }) {
  const T = useT();
  const { analysis, loading, error } = useRunAnalysis(run, true);
  const [followUpResults, setFollowUpResults] = React.useState({});
  const [runningFollowUp, setRunningFollowUp] = React.useState({});
  const [slackSent,       setSlackSent]       = React.useState(false);
  const [sending,         setSending]         = React.useState(false);
  const [activeTab,       setActiveTab]       = React.useState("analysis"); // analysis | followup | fix

  const SEV = { critical:T.red, high:T.orange, medium:T.yellow, low:T.green };

  const sendSlack = async () => {
    if (!analysis?.notify_message) return;
    setSending(true);
    await fetch(`${API}/api/workflow-results/share-slack`, {
      method:"POST", headers:{"Content-Type":"application/json"},
      body:JSON.stringify({
        run_id:run.run_id, check_name:"All checks",
        workflow_name:run.workflow_name,
        row_count:run.failed||0,
        severity:analysis.severity_assessment||"high",
        note:analysis.notify_message,
        sql:""
      })
    }).catch(()=>{});
    setSending(false); setSlackSent(true);
  };

  const runFollowUp = async (chk, i) => {
    setRunningFollowUp(p=>({...p,[i]:true}));
    const res = await fetch(`${API}/api/ai/run-follow-up`, {
      method:"POST", headers:{"Content-Type":"application/json"},
      body:JSON.stringify(chk)
    }).then(r=>r.json()).catch(e=>({error:e.message}));
    setFollowUpResults(p=>({...p,[i]:res}));
    setRunningFollowUp(p=>({...p,[i]:false}));
  };

  const failedChecks = (run.check_results||[]).filter(c=>!c.passed);
  const urgColor = SEV[analysis?.severity_assessment] || T.orange;

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.45)", zIndex:2000,
      display:"flex", alignItems:"center", justifyContent:"center" }}
      onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      <div style={{ background:T.card, borderRadius:16, width:"min(680px,95vw)",
        maxHeight:"88vh", display:"flex", flexDirection:"column",
        border:`1px solid ${T.border}`, boxShadow:"0 24px 80px rgba(0,0,0,0.25)" }}>

        {/* Header */}
        <div style={{ padding:"18px 22px", borderBottom:`1px solid ${T.border}`,
          display:"flex", alignItems:"center", gap:12, flexShrink:0 }}>
          <div style={{ width:36, height:36, borderRadius:10,
            background:`${urgColor}15`, display:"flex", alignItems:"center",
            justifyContent:"center", fontSize:18 }}>
            {analysis?.all_clear===false ? "⚠️" : loading ? "🤔" : "✅"}
          </div>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:14, fontWeight:700, color:T.text }}>
              WiziAgent Analysis — {run.workflow_name}
            </div>
            <div style={{ fontSize:11, color:T.muted, marginTop:1 }}>
              {run.failed||0} failed · {run.total_checks||0} total checks · {run.started_at?.slice(0,16)?.replace("T"," ")}
            </div>
          </div>
          {analysis?.severity_assessment && (
            <Badge label={analysis.severity_assessment} color={urgColor}/>
          )}
          <button onClick={onClose}
            style={{ background:"none", border:"none", cursor:"pointer",
              color:T.muted, fontSize:20, lineHeight:1 }}>×</button>
        </div>

        {/* Sub-tabs */}
        <div style={{ display:"flex", gap:0, borderBottom:`1px solid ${T.border}`, flexShrink:0 }}>
          {[
            {id:"analysis", label:"AI Analysis"},
            {id:"followup", label:`Follow-up (${(analysis?.follow_up_checks||[]).length})`},
            {id:"fix",      label:"Fix SQL"},
          ].map(tab=>(
            <button key={tab.id} onClick={()=>setActiveTab(tab.id)}
              style={{ padding:"9px 18px", fontSize:12, fontWeight:activeTab===tab.id?600:400,
                color:activeTab===tab.id?T.accent:T.muted, background:"none", border:"none",
                cursor:"pointer", borderBottom:activeTab===tab.id?`2px solid ${T.accent}`:"2px solid transparent",
                marginBottom:-1 }}>
              {tab.label}
            </button>
          ))}
        </div>

        {/* Body */}
        <div style={{ flex:1, overflowY:"auto", padding:"18px 22px" }}>

          {loading && (
            <div style={{ display:"flex", gap:10, alignItems:"center",
              padding:"20px 0", color:T.muted, fontSize:12 }}>
              <Spinner size={16}/> WiziAgent is analysing the results…
            </div>
          )}

          {error && !loading && (
            <div style={{ color:T.red, fontSize:12, padding:"10px 0" }}>
              AI analysis unavailable: {error}
            </div>
          )}

          {/* Analysis tab */}
          {activeTab==="analysis" && analysis && !loading && (
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>

              {/* Summary */}
              <div style={{ padding:"14px 16px", borderRadius:10,
                background:`${urgColor}08`, border:`1px solid ${urgColor}20` }}>
                <div style={{ fontSize:11, fontWeight:700, color:urgColor, marginBottom:6,
                  textTransform:"uppercase", letterSpacing:"0.05em" }}>Summary</div>
                <div style={{ fontSize:13, color:T.text, lineHeight:1.6 }}>{analysis.summary}</div>
              </div>

              {/* Root cause */}
              {analysis.root_cause && (
                <div>
                  <div style={{ fontSize:11, fontWeight:700, color:T.muted, marginBottom:5,
                    textTransform:"uppercase", letterSpacing:"0.05em" }}>Root Cause</div>
                  <div style={{ fontSize:12, color:T.text2, lineHeight:1.6,
                    padding:"10px 14px", borderRadius:8, background:T.surface,
                    border:`1px solid ${T.border}` }}>
                    🔍 {analysis.root_cause}
                  </div>
                </div>
              )}

              {/* Failed checks summary */}
              <div>
                <div style={{ fontSize:11, fontWeight:700, color:T.muted, marginBottom:5,
                  textTransform:"uppercase", letterSpacing:"0.05em" }}>
                  Failed Checks ({failedChecks.length})
                </div>
                <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
                  {failedChecks.map((c,i)=>(
                    <div key={c.id||c.name||i} style={{ display:"flex", alignItems:"center", gap:8,
                      padding:"8px 12px", borderRadius:7, background:T.surface,
                      border:`1px solid ${T.border}` }}>
                      <X size={11} color={T.red}/>
                      <span style={{ fontSize:12, color:T.text, flex:1 }}>{c.name}</span>
                      <span style={{ fontSize:11, color:T.red, fontWeight:700 }}>
                        {c.row_count} rows
                      </span>
                      <Badge label={c.severity||"high"} color={SEV_COLOR[c.severity]||T.muted}/>
                    </div>
                  ))}
                </div>
              </div>

              {/* Suggested actions */}
              {(analysis.suggested_actions||[]).length > 0 && (
                <div>
                  <div style={{ fontSize:11, fontWeight:700, color:T.muted, marginBottom:5,
                    textTransform:"uppercase", letterSpacing:"0.05em" }}>AI Recommends</div>
                  <div style={{ display:"flex", flexDirection:"column", gap:4 }}>
                    {analysis.suggested_actions.map((a,i)=>(
                      <div key={i} style={{ fontSize:12, color:T.text2, display:"flex",
                        gap:8, alignItems:"flex-start" }}>
                        <span style={{ color:T.accent, flexShrink:0 }}>→</span> {a}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Follow-up checks tab */}
          {activeTab==="followup" && (
            <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
              {(!analysis?.follow_up_checks?.length) && !loading && (
                <div style={{ color:T.dim, fontSize:12, textAlign:"center", padding:"20px 0" }}>
                  {loading ? <Spinner size={16}/> : "No follow-up checks suggested"}
                </div>
              )}
              {(analysis?.follow_up_checks||[]).map((chk,i)=>{
                const res = followUpResults[i];
                return (
                  <div key={chk.name||i} style={{ borderRadius:10, border:`1px solid ${T.border}`,
                    overflow:"hidden" }}>
                    <div style={{ padding:"12px 14px", background:T.surface }}>
                      <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:5 }}>
                        <span style={{ fontSize:12, fontWeight:700, color:T.text }}>{chk.name}</span>
                        {res && (
                          <Badge label={res.passed?"✓ Passed":"✗ Failed"}
                            color={res.passed?T.green:T.red}/>
                        )}
                      </div>
                      <div style={{ fontSize:11, color:T.muted, marginBottom:8 }}>{chk.reason}</div>
                      <pre style={{ fontSize:10, fontFamily:"monospace", color:T.text2,
                        background:T.card, padding:"8px 10px", borderRadius:6,
                        border:`1px solid ${T.border}`, margin:0, whiteSpace:"pre-wrap" }}>
                        {chk.sql}
                      </pre>
                      {res?.rows?.length > 0 && (
                        <div style={{ marginTop:8, fontSize:10, color:T.muted }}>
                          {res.row_count} rows · columns: {res.columns?.join(", ")}
                        </div>
                      )}
                    </div>
                    <div style={{ padding:"8px 14px", borderTop:`1px solid ${T.border}`,
                      display:"flex", gap:8 }}>
                      <Btn size="sm" onClick={()=>runFollowUp(chk,i)}
                        disabled={!!runningFollowUp[i]}>
                        {runningFollowUp[i]?<Spinner size={10}/>:<Play size={10}/>} Run Check
                      </Btn>
                      {res && !res.error && (
                        <span style={{ fontSize:10, color:res.passed?T.green:T.red,
                          display:"flex", alignItems:"center", gap:4 }}>
                          {res.row_count} rows returned
                        </span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Fix SQL tab */}
          {activeTab==="fix" && (
            <div>
              {analysis?.fix_sql ? (
                <div>
                  <div style={{ fontSize:11, color:T.muted, marginBottom:8 }}>
                    ⚠️ Review carefully before running. This SQL will modify data.
                  </div>
                  <pre style={{ fontSize:11, fontFamily:"monospace", color:T.text2,
                    background:T.surface, padding:"14px 16px", borderRadius:10,
                    border:`1px solid ${T.border}`, whiteSpace:"pre-wrap",
                    margin:"0 0 12px" }}>
                    {analysis.fix_sql}
                  </pre>
                  <Btn size="sm" onClick={()=>onSendToTriage?.(run, analysis?.fix_sql)}
                    style={{ background:T.orange, color:"white", border:"none" }}>
                    Send to Triage for review →
                  </Btn>
                </div>
              ) : !loading && (
                <div style={{ color:T.dim, fontSize:12, textAlign:"center", padding:"20px 0" }}>
                  No safe fix SQL available for this issue
                </div>
              )}
              {loading && <div style={{ textAlign:"center", padding:"20px 0" }}><Spinner size={20}/></div>}
            </div>
          )}
        </div>

        {/* Footer actions */}
        <div style={{ padding:"14px 22px", borderTop:`1px solid ${T.border}`,
          display:"flex", gap:8, flexShrink:0, flexWrap:"wrap" }}>
          <Btn onClick={()=>onSendToTriage?.(run)}
            style={{ background:T.orange, color:"white", border:"none" }}>
            → Send to Triage
          </Btn>
          <Btn onClick={sendSlack} disabled={sending||slackSent} variant="ghost">
            {sending?<Spinner size={10}/>:slackSent?"✓ Sent":"Notify Slack"}
          </Btn>
          {onNavigateResults && (
            <Btn onClick={()=>{ onClose(); onNavigateResults(); }} variant="ghost">
              📊 View Full Data
            </Btn>
          )}
          <Btn onClick={onClose} variant="ghost" style={{ marginLeft:"auto" }}>Dismiss</Btn>
        </div>
      </div>
    </div>
  );
}


// ── 2. AI BRIEF PANEL — AI section inside Daily Brief ─────────────────────────
function AiBriefPanel() {
  const T = useT();
  const [brief,   setBrief]   = React.useState(null);
  const [loading, setLoading] = React.useState(false);
  const [error,   setError]   = React.useState(null);
  const [expanded,setExpanded]= React.useState(true);

  const CACHE_KEY = "wz_brief_cache";
  const CACHE_TTL  = 15 * 60 * 1000; // 15 minutes

  const load = async (force=false) => {
    if (!force) {
      try {
        const cached = JSON.parse(sessionStorage.getItem(CACHE_KEY)||"null");
        if (cached && Date.now() - cached.ts < CACHE_TTL) {
          setBrief(cached.data); return;
        }
      } catch(e) {}
    }
    setLoading(true); setError(null);
    try {
      const res = await fetch(`${API}/api/ai/daily-brief`, {
        method:"POST", headers:{"Content-Type":"application/json"}, body:"{}"
      });
      const d = await res.json();
      if (d.error) setError(d.error);
      else {
        setBrief(d);
        try { sessionStorage.setItem(CACHE_KEY, JSON.stringify({data:d, ts:Date.now()})); } catch(e) {}
      }
    } catch(e) { setError(e.message); }
    setLoading(false);
  };

  React.useEffect(()=>{ load(); }, []);

  const URGENCY_COLOR = { critical:T.red, high:T.orange, medium:T.yellow, low:T.green };
  const score = brief?.health_score;
  const scoreColor = score>=80?T.green:score>=60?T.orange:T.red;

  return (
    <div style={{ padding:"16px 20px", borderRadius:12, marginBottom:20,
      background:T.surface, border:`1px solid ${T.border}` }}>
      <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom: expanded?12:0 }}>
        <div style={{ width:32, height:32, borderRadius:8,
          background:`${T.purple}15`, display:"flex", alignItems:"center",
          justifyContent:"center", fontSize:16 }}>🤖</div>
        <div style={{ flex:1 }}>
          <div style={{ fontSize:12, fontWeight:700, color:T.text }}>WiziAgent Brief</div>
          {brief?.headline && (
            <div style={{ fontSize:11, color:T.muted, marginTop:1 }}>{brief.headline}</div>
          )}
        </div>
        <button onClick={()=>load(true)} disabled={loading}
          style={{ background:"none", border:"none", cursor:loading?"not-allowed":"pointer",
            color:T.muted, fontSize:13, padding:"2px 6px", borderRadius:5, opacity:loading?0.4:1 }}
          title="Refresh brief">↺</button>
        {score !== undefined && (
          <div style={{ textAlign:"center", padding:"4px 10px", borderRadius:8,
            background:`${scoreColor}12`, border:`1px solid ${scoreColor}25` }}>
            <div style={{ fontSize:18, fontWeight:800, color:scoreColor }}>{score}</div>
            <div style={{ fontSize:9, color:T.muted }}>Health</div>
          </div>
        )}
        <Btn size="sm" variant="ghost" onClick={load} disabled={loading}>
          {loading?<Spinner size={10}/>:<RefreshCw size={10}/>}
        </Btn>
        <button onClick={()=>setExpanded(p=>!p)}
          style={{ background:"none", border:"none", cursor:"pointer",
            color:T.muted, fontSize:14 }}>
          {expanded?"▴":"▾"}
        </button>
      </div>

      {expanded && (
        <>
          {loading && (
            <div style={{ display:"flex", gap:8, alignItems:"center",
              color:T.muted, fontSize:11, padding:"8px 0" }}>
              <Spinner size={12}/> Analysing pipeline health…
            </div>
          )}
          {error && <div style={{ color:T.red, fontSize:11 }}>AI unavailable: {error}</div>}

          {brief && !loading && (
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {brief.all_clear ? (
                <div style={{ display:"flex", alignItems:"center", gap:8,
                  padding:"10px 14px", borderRadius:8,
                  background:`${T.green}08`, border:`1px solid ${T.green}25` }}>
                  <CheckCircle size={14} color={T.green}/>
                  <span style={{ fontSize:12, color:T.green, fontWeight:600 }}>
                    All clear — pipeline is healthy
                  </span>
                </div>
              ) : (
                (brief.priority_items||[]).map((item,i)=>(
                  <div key={item.id||item.title||i} style={{ display:"flex", alignItems:"flex-start", gap:10,
                    padding:"10px 14px", borderRadius:8,
                    background:`${URGENCY_COLOR[item.urgency]||T.muted}08`,
                    border:`1px solid ${URGENCY_COLOR[item.urgency]||T.muted}20` }}>
                    <div style={{ width:20, height:20, borderRadius:"50%", flexShrink:0,
                      background:`${URGENCY_COLOR[item.urgency]||T.muted}20`,
                      display:"flex", alignItems:"center", justifyContent:"center",
                      fontSize:10, fontWeight:800,
                      color:URGENCY_COLOR[item.urgency]||T.muted }}>
                      {item.priority}
                    </div>
                    <div style={{ flex:1 }}>
                      <div style={{ fontSize:12, fontWeight:700, color:T.text }}>{item.title}</div>
                      <div style={{ fontSize:11, color:T.muted, marginTop:2 }}>{item.detail}</div>
                    </div>
                    <Badge label={item.urgency} color={URGENCY_COLOR[item.urgency]||T.muted}/>
                  </div>
                ))
              )}

              {/* Top 3 actions — derived from priority_items, zero extra tokens */}
              {(brief.priority_items||[]).length > 0 && (() => {
                const top3 = (brief.priority_items||[]).slice(0,3);
                return (
                  <div style={{ padding:"10px 14px", borderRadius:8,
                    background:`linear-gradient(135deg,${T.accent}08,${T.purple}06)`,
                    border:`1px solid ${T.accent}20`, marginTop:4 }}>
                    <div style={{ fontSize:10, fontWeight:700, color:T.accent,
                      textTransform:"uppercase", letterSpacing:"0.06em", marginBottom:6 }}>
                      ✨ Top {top3.length} actions today
                    </div>
                    {top3.map((item,i)=>(
                      <div key={item.id||i} style={{ display:"flex", alignItems:"center", gap:8,
                        fontSize:11, color:T.text2, marginBottom:i<top3.length-1?4:0 }}>
                        <span style={{ width:16, height:16, borderRadius:"50%", flexShrink:0,
                          background:`${T.accent}20`, display:"flex", alignItems:"center",
                          justifyContent:"center", fontSize:9, fontWeight:800, color:T.accent }}>
                          {i+1}
                        </span>
                        <span style={{ flex:1 }}>{item.title}</span>
                        <span style={{ fontSize:9, padding:"1px 6px", borderRadius:4,
                          background:`${(URGENCY_COLOR[item.urgency]||T.muted)}15`,
                          color:URGENCY_COLOR[item.urgency]||T.muted, fontWeight:600 }}>
                          {item.urgency}
                        </span>
                      </div>
                    ))}
                  </div>
                );
              })()}

              {brief.recommendation && (
                <div style={{ fontSize:11, color:T.accent, padding:"8px 14px",
                  borderRadius:8, background:`${T.accent}06`,
                  border:`1px solid ${T.accent}15`, marginTop:2 }}>
                  💡 {brief.recommendation}
                </div>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}


// ── 3. FLOATING ASSISTANT — persistent AI chat with full context ───────────────
// ─── WiziAgent — Agentic assistant with real tool execution ──────────────────

const TOOL_META = {
  run_sql:           { icon:"🔍", label:"Running SQL",       color:"#6366F1" },
  navigate:          { icon:"🧭", label:"Navigating",        color:"#8B5CF6" },
  run_workflow:      { icon:"▶",  label:"Running workflow",  color:"#10B981" },
  run_dataflow:      { icon:"▶",  label:"Running dataflow",  color:"#10B981" },
  get_workflow_status:{ icon:"📋", label:"Checking workflows",color:"#6366F1" },
  get_dataflows:     { icon:"📋", label:"Checking dataflows",color:"#6366F1" },
  get_recent_results:{ icon:"📊", label:"Fetching results",  color:"#F59E0B" },
  get_kpis:          { icon:"📈", label:"Fetching KPIs",     color:"#06B6D4" },
  get_alerts:        { icon:"⚠️", label:"Checking alerts",   color:"#EF4444" },
  get_triage_issues: { icon:"🔎", label:"Scanning issues",   color:"#EF4444" },
  get_schema:        { icon:"🗄️", label:"Reading schema",    color:"#6B7280" },
  create_dataflow:   { icon:"✨", label:"Creating dataflow", color:"#10B981" },
  get_schedules:     { icon:"🕐", label:"Checking schedules",color:"#8B5CF6" },
};

// Render a tool result compactly — warm premium card
function ToolResultBlock({ tool, result, T, WZ }) {
  WZ = WZ || WIZI_THEMES.sand;
  const meta = TOOL_META[tool] || { icon:"🔧", label:tool, color:"#7C5C3E" };
  const [expanded, setExpanded] = React.useState(false);

  const summary = React.useMemo(() => {
    if (!result) return "Done";
    if (result.error) return `Error: ${result.error}`;
    if (tool==="run_sql") {
      if (result.row_count===0) return "0 rows returned";
      return `${result.row_count} row${result.row_count!==1?"s":""} · ${(result.columns||[]).slice(0,3).join(", ")}`;
    }
    if (tool==="navigate") return `→ ${result.tab}`;
    if (tool==="run_workflow"||tool==="run_dataflow")
      return result.status==="pass"||result.status==="clean"
        ? `✓ All ${result.total_checks||0} checks passed`
        : `✗ ${result.failed||0}/${result.total_checks||0} failed`;
    if (tool==="get_triage_issues") { const n=(result.issues||[]).length; return n===0?"No open issues":`${n} issue${n!==1?"s":""} found`; }
    if (tool==="get_recent_runs") { const r=result.runs||[]; const f=r.filter(x=>x.status!=="clean"&&x.status!=="pass").length; return `${r.length} runs · ${f} failed`; }
    if (tool==="get_dataflows") { const d=result.dataflows||[]; return `${d.length} dataflows loaded`; }
    if (tool==="get_health") return `Health ${result.health_score??'?'}/100 · ${result.issues||0} issues`;
    if (Array.isArray(result)) return `${result.length} item${result.length!==1?"s":""}`;
    return "Done";
  }, [result, tool]);

  const hasDetail = result && !result.error && tool==="run_sql" && result.rows?.length>0;
  const isErr = !!result?.error;

  return (
    <div style={{ margin:"3px 0 8px 30px" }}>
      <div style={{ display:"flex", alignItems:"center", gap:7, padding:"6px 11px",
        borderRadius:8, background: isErr?"#FEF2F2":WZ.card,
        border:`1px solid ${isErr?"#FECACA":WZ.border}`, fontSize:11 }}>
        <span style={{fontSize:13}}>{meta.icon}</span>
        <span style={{ color:isErr?"#B91C1C":WZ.accent, fontWeight:700,
          fontSize:10, letterSpacing:"0.04em", textTransform:"uppercase" }}>{meta.label}</span>
        <span style={{ color: isErr?"#DC2626":WZ.muted, flex:1, fontSize:11 }}>{summary}</span>
        {hasDetail && (
          <button onClick={()=>setExpanded(p=>!p)}
            style={{ background:"none", border:"1px solid #E8E0D0", cursor:"pointer",
              color:WZ.muted, fontSize:9, fontWeight:700, padding:"1px 7px",
              borderRadius:4, letterSpacing:"0.04em", border:`1px solid ${WZ.border}` }}>
            {expanded?"▲":"▼ show"}
          </button>
        )}
      </div>
      {expanded && hasDetail && (
        <div style={{ marginTop:3, borderRadius:7, overflow:"auto",
          maxHeight:180, border:`1px solid ${WZ.border}`, background:WZ.panel }}>
          <table style={{ borderCollapse:"collapse", fontSize:10.5, width:"100%", fontFamily:"monospace" }}>
            <thead>
              <tr style={{ background:WZ.chipHov }}>
                {result.columns.map(c=>(
                  <th key={c} style={{ padding:"5px 10px", textAlign:"left",
                    fontSize:9, fontWeight:800, color:WZ.accent, borderBottom:`1px solid ${WZ.border}`,
                    textTransform:"uppercase", letterSpacing:"0.06em", whiteSpace:"nowrap" }}>{c}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {result.rows.slice(0,10).map((row,i)=>(
                <tr key={i} style={{ borderBottom:`1px solid ${WZ.border2}` }}>
                  {result.columns.map(c=>(
                    <td key={c} style={{ padding:"4px 10px",
                      color:row[c]===null?"#EF4444":WZ.text2, whiteSpace:"nowrap" }}>
                      {row[c]===null?"NULL":String(row[c]).slice(0,40)}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
          {result.rows.length>10 && (
            <div style={{ padding:"3px 10px", fontSize:9, color:WZ.muted, background:WZ.chip }}>
              +{result.rows.length-10} more rows
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function AgentMessage({ msg, onNavigate, T, WZ }) {
  WZ = WZ || WIZI_THEMES.sand;
  if (msg.role==="user") {
    return (
      <div style={{ display:"flex", justifyContent:"flex-end", marginBottom:14 }}>
        <div style={{ maxWidth:"78%", padding:"10px 15px", borderRadius:16,
          borderBottomRightRadius:3, fontSize:12.5, lineHeight:1.6,
          background:WZ.userBubble, color:WZ.userText,
          whiteSpace:"pre-wrap", wordBreak:"break-word",
          boxShadow:`0 2px 12px ${WZ.btnPulse}` }}>
          {msg.text}
        </div>
      </div>
    );
  }

  if (msg.role==="thinking") {
    const label = msg.text || "Thinking…";
    const isTooling = label!=="Thinking…" && label!=="";
    return (
      <div style={{ display:"flex", alignItems:"center", gap:9, marginBottom:10,
        padding:"9px 13px", maxWidth:"82%",
        background:WZ.card, borderRadius:10,
        border:`1px solid ${WZ.border}`, boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>
        {isTooling ? (
          <div style={{ width:18, height:18, borderRadius:5, flexShrink:0,
            background:WZ.btn, display:"flex", alignItems:"center",
            justifyContent:"center", fontSize:9, color:WZ.aiBubble,
            animation:"pulse 0.9s infinite" }}>⚡</div>
        ) : (
          <div style={{ display:"flex", gap:3, flexShrink:0 }}>
            {[0,1,2].map(i=>(
              <div key={i} style={{ width:5, height:5, borderRadius:"50%",
                background:WZ.dim, animation:`bounce 1.1s ${i*0.18}s infinite` }}/>
            ))}
          </div>
        )}
        <span style={{ fontSize:11, color:WZ.accent, fontStyle:"italic", fontWeight:500 }}>
          {label || "Thinking…"}
        </span>
      </div>
    );
  }

  if (msg.role==="tool_call") {
    const meta = TOOL_META[msg.tool] || { icon:"🔧", label:msg.tool };
    return (
      <div style={{ display:"inline-flex", alignItems:"center", gap:6, padding:"4px 10px",
        marginBottom:5, fontSize:10, background:WZ.chip, border:`1px solid ${WZ.chipBorder}`,
        borderRadius:6, maxWidth:"fit-content", color:WZ.accent, fontWeight:600 }}>
        <span style={{fontSize:11}}>{meta.icon}</span>{meta.label}…
      </div>
    );
  }

  return (
    <div style={{ marginBottom:16 }}>
      {(msg.steps||[]).filter(s=>s.type==="tool_result").map((s,i)=>(
        <ToolResultBlock key={s.call_id||s.tool||i} tool={s.tool} result={s.result} T={T} WZ={WZ}/>
      ))}
      {(msg.actions||[]).filter(a=>a.type==="navigate").map((a,i)=>(
        <div key={"nav"+i} onClick={()=>onNavigate(a.tab)}
          style={{ display:"inline-flex", alignItems:"center", gap:6,
            padding:"5px 12px", borderRadius:8, marginBottom:8, cursor:"pointer",
            background:WZ.chip, color:WZ.accent,
            border:`1px solid ${WZ.chipBorder}`, fontSize:11, fontWeight:600, transition:"all 0.15s",
            boxShadow:"0 1px 3px rgba(0,0,0,0.06)" }}
          onMouseEnter={e=>{e.currentTarget.style.background=WZ.chipHov;e.currentTarget.style.transform="translateY(-1px)";}}
          onMouseLeave={e=>{e.currentTarget.style.background=WZ.chip;e.currentTarget.style.transform="translateY(0)";}}>
          🧭 Go to {a.tab} →
        </div>
      ))}
      {(msg.actions||[]).filter(a=>a.type==="created_dataflow").map((a,i)=>(
        <div key={"df"+i} onClick={()=>onNavigate("dataflows")}
          style={{ display:"inline-flex", alignItems:"center", gap:6,
            padding:"5px 12px", borderRadius:8, marginBottom:8, cursor:"pointer",
            background:"#F0FAF5", color:"#15803D",
            border:"1px solid #BBF7D0", fontSize:11, fontWeight:600 }}
          onMouseEnter={e=>e.currentTarget.style.background="#DCFCE7"}
          onMouseLeave={e=>e.currentTarget.style.background="#F0FAF5"}>
          ✦ Dataflow created — view →
        </div>
      ))}
      {msg.text && (
        <div style={{ display:"flex", gap:9, alignItems:"flex-start" }}>
          <div style={{ width:24, height:24, borderRadius:7, flexShrink:0, marginTop:2,
            background:WZ.avatarBg, border:`1px solid ${WZ.border}`,
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:11, color:WZ.avatarText, fontWeight:700 }}>✦</div>
          <div style={{ flex:1, padding:"11px 14px", borderRadius:14,
            borderTopLeftRadius:3, fontSize:12.5, lineHeight:1.7,
            color:WZ.aiText, background:WZ.aiBubble,
            border:`1px solid ${WZ.border}`,
            boxShadow:"0 2px 8px rgba(0,0,0,0.05)",
            whiteSpace:"pre-wrap", wordBreak:"break-word",
            maxWidth:"calc(100% - 33px)" }}>
            {msg.text}
          </div>
        </div>
      )}
    </div>
  );
}

// ── useLiveChips — reactive suggestion chips based on current app state ────────
function useLiveChips(currentTab, currentRun) {
  return React.useMemo(() => {
    const chips = [];

    // 1. If there's a live run result with failures — most urgent
    if (currentRun) {
      const failCount = (currentRun.results||[]).filter(r=>r.status!=="pass").length;
      const wfName = currentRun.workflow_name || currentRun.name;
      if (failCount > 0) {
        chips.push(`Why did ${wfName ? `"${wfName}"` : "the last run"} fail?`);
        chips.push(`Send failed checks to triage`);
      } else if (failCount === 0 && currentRun.results?.length > 0) {
        chips.push(`Summarise the last run`);
      }
    }

    // 2. Recent workflow failures from session storage
    try {
      const runs = JSON.parse(localStorage.getItem("wz_wf_runhistory_v1")||"[]");
      const failed = runs.filter(r => r.status !== "clean" && r.status !== "pass");
      if (failed.length && chips.length < 2) {
        const wf = failed[0];
        chips.push(`What went wrong in "${wf.workflow_name || wf.name || "last workflow"}"?`);
      }
    } catch {}

    // 3. Open triage issues
    try {
      const issues = JSON.parse(sessionStorage.getItem("wz_pendingIssues")||"[]");
      const critical = issues.filter(i => i.severity === "critical");
      if (critical.length > 0) {
        chips.push(`Explain the ${critical.length} critical issue${critical.length>1?"s":""} in triage`);
      } else if (issues.length > 0 && chips.length < 3) {
        chips.push(`What are the open triage issues?`);
      }
    } catch {}

    // 4. Time-of-day aware — ads data check (after 3:30 PM IST = 10:00 UTC)
    try {
      const utcHour = new Date().getUTCHours();
      const utcMin  = new Date().getUTCMinutes();
      const pastAdsWindow = utcHour > 10 || (utcHour === 10 && utcMin >= 0);
      if (pastAdsWindow && chips.length < 4) {
        chips.push("Is today's campaign report data loaded?");
      }
    } catch {}

    // 5. Brief health score
    try {
      const br = JSON.parse(sessionStorage.getItem("wz_brief")||"null");
      if (br?.health_score !== undefined && br.health_score < 80 && chips.length < 4) {
        chips.push(`Health is ${br.health_score}/100 — what's dragging it down?`);
      }
    } catch {}

    // 6. Tab-aware fallback chips
    if (chips.length < 3) {
      const tabChips = {
        workflows:  ["Show my workflow pass rates", "Run all critical workflows"],
        triage:     ["Summarise open issues by severity", "Which issues need immediate attention?"],
        dataflows:  ["Which dataflows haven't run today?", "Create a null check for mws.orders"],
        results:    ["Compare today's results to yesterday", "Which checks failed most often this week?"],
        monitor:    ["Show me tables with no data today", "Which report types failed most this week?"],
        scheduler:  ["What's scheduled to run next?", "Are any schedules overdue?"],
        autopilot:  ["What did AutoPilot detect today?", "Run the main detection pipeline"],
      };
      const extra = tabChips[currentTab] || [
        "What failed in the last 24 hours?",
        "Show me failed downloads today",
        "What's my current inventory health?",
        "Are there any stale tables?",
      ];
      extra.forEach(c => { if (!chips.includes(c)) chips.push(c); });
    }

    return chips.slice(0, 5);
  }, [currentTab, currentRun]);
}

// ── Agent memory helpers ──────────────────────────────────────────────────────
const MEM_KEY = "wz_agent_memory_v1";
const MEM_MAX = 10;
function memLoad() { try { return JSON.parse(localStorage.getItem(MEM_KEY)||"[]"); } catch { return []; } }
function memSave(convos) { try { localStorage.setItem(MEM_KEY, JSON.stringify(convos.slice(-MEM_MAX))); } catch {} }
function memSummary() {
  const convos = memLoad();
  if (!convos.length) return "";
  return "Past sessions (newest first):\n" + convos.slice(-5).reverse().map((c,i)=>
    `[${i+1}] ${c.ts} — User: "${c.user}" → "${c.reply.slice(0,100)}${c.reply.length>100?"…":""}"`
  ).join("\n");
}

